-- Step 1: Add explanation column if it does not exist
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name='questions' AND column_name='explanation'
  ) THEN
    ALTER TABLE questions ADD COLUMN explanation TEXT;
  END IF;
END $$;

BEGIN;

UPDATE questions SET explanation = 'Iron is attracted to magnets, so when you pass a magnet over a mixture of iron filings and sulphur, the iron filings will stick to the magnet while the sulphur stays behind. This works because iron has magnetic properties that allow it to be pulled by magnets. Sulphur is non-magnetic, but that''s not the main reason we can separate them – the key is that iron IS magnetic, making it easy to pick out of the mixture.' WHERE id = '0990f308-0a9c-412a-b2c2-f2b10669311d';
UPDATE questions SET explanation = 'An open switch is shown by a break or gap in the circuit symbol, which means the circuit is not complete and electricity cannot flow through it. When a switch is closed, the symbol shows a complete connection with no gap, allowing current to pass through. Think of it like a bridge - when the bridge is broken (open), you cannot cross, but when it''s complete (closed), you can travel across it.' WHERE id = '2a0f19bb-8c87-46c4-9f94-f42a4a6319af';
UPDATE questions SET explanation = 'The effort is the force you apply to make a lever work, and part A shows where you push or pull on the lever to move something. While the whole object is indeed a lever, part A specifically marks the point where your force is applied. Think of opening a bottle with a bottle opener - your hand pushes at one spot (the effort), and that''s different from the tool itself or where the bottle cap sits.' WHERE id = '26c3c438-6ae3-48ba-a379-1c9a41b6e6d1';
UPDATE questions SET explanation = 'A crowbar is the best lever to lift a heavy rock because it works like a strong arm that helps you push down on one end to lift something heavy on the other end. While a wheelbarrow is also a lever, it is designed to carry and move things from one place to another, not to lift heavy objects off the ground. A crowbar gives you the most lifting power when you need to get underneath and raise a heavy rock.' WHERE id = '25f631aa-6ff6-4cef-90ad-3f7c6ad598a1';
UPDATE questions SET explanation = 'Lightning looks for the tallest objects to strike, so standing under a tree during a thunderstorm is very dangerous because the tree attracts lightning and you could be struck too. Lying down is actually safer than standing because you make yourself smaller and less likely to be hit. The other options are all good safety actions that help protect you from lightning, not things that increase your risk.' WHERE id = '7f225d90-4500-40f6-828c-62752137a085';
UPDATE questions SET explanation = 'Transparent objects are materials that allow light to pass through them so you can see clearly through to the other side. Wood is not transparent because it blocks light completely, making it impossible to see through it. Windscreens, clear glass, and glass bottles all let light pass through them, which is why you can see through these objects.' WHERE id = 'ab0b4273-8b17-4fcd-a00c-8fad14bed951';
UPDATE questions SET explanation = 'A thermometer works by measuring how liquids expand or contract with temperature changes, not by bending light rays. Lenses, telescopes, and binoculars all use refraction, which is when light bends as it passes through curved glass to help us see things more clearly or make them look bigger. The thermometer simply shows us the level of liquid inside it, so no light bending is needed for it to work.' WHERE id = '2389b066-abc2-47cf-bb43-e18b9d4dddd8';
UPDATE questions SET explanation = 'Heat moves from hot places to cold places in three main ways: conduction (through touching), convection (through liquids and gases moving), and radiation (through rays like sunlight). Convection is when heated liquid or air rises and cooler parts sink down, creating a movement that transfers heat—like when you see steam rising from hot water. Condensation is actually when water vapor turns into liquid, which is a completely different process and not a way heat travels.' WHERE id = 'eb53e5c7-ca21-402a-802e-708937939253';
UPDATE questions SET explanation = 'An indicator is a special substance that changes color to show us whether something is alkaline, acidic, or neutral. Litmus paper is actually one type of indicator, so it might seem like a good answer, but indicators include many other substances like universal indicator solution and red cabbage juice that can test for alkaline or neutral substances. Think of "indicator" as the general name for all substances that help us identify acids and alkalis!' WHERE id = 'f0177d95-4daf-483b-9326-e02544fb7026';
UPDATE questions SET explanation = 'When water is heated from the top, the hot water stays at the top because convection causes hot liquids to rise naturally, so the ice at the bottom doesn''t melt. This experiment proves convection in liquids because if heat moved through the water by conduction (option B), the ice would have melted since conduction spreads heat evenly through liquids. The setup cleverly shows that convection currents only work when you heat from below, not from above.' WHERE id = 'cdd2b19a-5d80-4443-b162-3be1e169ded3';
UPDATE questions SET explanation = 'Hard water contains dissolved minerals like calcium and magnesium, and washing soda works by chemically reacting with these minerals to remove them from the water, making it soft. While boiling can remove some hardness, it only works for temporary hardness and doesn''t remove all the minerals like washing soda does. Filtration and sedimentation only remove solid particles that you can see, but they cannot remove dissolved minerals that make water hard.' WHERE id = 'b6f5ca6a-a7ee-4525-b21e-325922837b0d';
UPDATE questions SET explanation = 'An anemometer is the special instrument that measures how fast the wind is moving, which we call wind speed - it has cups that spin faster when the wind blows harder. While option A might seem close because the instrument does involve wind, it''s not complete enough because we need to know the specific measurement it gives us, which is the speed of that wind in units like kilometres per hour. The spinning cups don''t measure air pressure or temperature at all - those require completely different instruments.' WHERE id = 'da973b33-f6a5-49c5-8a13-7535bdfed409';
UPDATE questions SET explanation = 'When we walk, our shoes push against the ground and the ground pushes back, creating friction that stops us from slipping - without this friction, we would slide around like on ice! Activities like crying, watching, or reading don''t involve surfaces rubbing together, so they don''t create friction. Friction is a force that happens when two surfaces move against each other, which is exactly what happens between your feet and the ground when you walk.' WHERE id = 'd2e8d669-e101-43e0-8f63-4a0316577c82';
UPDATE questions SET explanation = 'In a series circuit, there is only one path for electricity to flow through, which means all the components are connected one after another in a single loop. Circuit C shows this arrangement where the current must pass through each component in turn with no branches or alternative routes. If you see a circuit with multiple paths or branches where the current can split up, that would be a parallel circuit, not a series circuit.' WHERE id = '6b07a47b-966f-4328-8a49-f3e73958fbd4';
UPDATE questions SET explanation = 'When you rub clothes together, they can build up charges that stay in one place until they suddenly jump as a spark - this is called static electricity. Current electricity is different because it flows continuously through wires in a circuit, like the electricity that powers your lights at home. The sparks you see when getting undressed are a quick release of static charge that built up from friction.' WHERE id = '22703dd0-c309-4ea1-ac6a-8c50748f4110';
UPDATE questions SET explanation = 'When a fine powder is mixed with water and creates a milky appearance, it means the particles are floating throughout the water but have not dissolved—this is called a suspension. While it is true that this is a type of mixture, the more specific and correct scientific term is suspension because the powder particles remain separate and will eventually settle at the bottom if left to stand. A solution would be clear, not milky, because in solutions the particles completely dissolve and disappear into the liquid.' WHERE id = '51398958-fa9f-4edb-af41-ee6844f99665';
UPDATE questions SET explanation = 'At a cold front, a mass of cold air moves in and pushes underneath the warm air that was there before, so cold air replaces warm air. While it''s true that warm air does rise when the cold air pushes under it (which is why option C might seem correct), that''s what happens during the process, not what a cold front actually means – a cold front is specifically about cold air taking the place of warm air in an area.' WHERE id = '22fdf2b1-b6c9-4ce0-a26d-ae0e43b345a6';
UPDATE questions SET explanation = 'When two surfaces rub against each other, like when you push a desk across the floor or rub your hands together, the force that resists this movement is called friction force. This force always acts to slow down or stop the rubbing motion between the surfaces. Gravitational force is different because it pulls objects downward toward the Earth, not sideways between rubbing surfaces.' WHERE id = '6fe7bef6-100b-4175-a337-e0666774e50e';
UPDATE questions SET explanation = 'A population is a group of the same kind of animal living together in one area, so all those guinea fowl near your cattle post form a population. You might think it''s a species, but species refers to the type or kind of animal itself (guinea fowl), not the actual group of birds living in that place. A community would include all the different types of living things in that area, like the guinea fowl, the cattle, grass, and other animals together.' WHERE id = '810de694-13cf-40ed-a975-94787e682ccc';
UPDATE questions SET explanation = 'When light passes from one material to another (like from air into water), it changes speed and bends at an angle - this bending is called refraction. You might confuse this with option A, but light travelling through an object is just transmission, not refraction - the key is that refraction specifically means the light ray bends when it enters a different material. This is why a straw looks bent when you put it in a glass of water!' WHERE id = '4ef185ce-1331-408a-bff0-7879ff5dca10';
UPDATE questions SET explanation = 'When scientists use evidence and patterns they''ve observed to say what will happen in the future, they are predicting. For example, scientists predict when the rainy season will come or when a plant will flower based on data they''ve collected. A hypothesis is different because it''s just an educated guess that scientists make before they test something, while predicting uses information we already know to forecast future events.' WHERE id = 'c6ebfc04-4d6c-4997-9cf8-54fed8301949';
UPDATE questions SET explanation = 'Boiling happens only when water reaches exactly 100°C (its boiling point), which is why we say it occurs at a fixed temperature. Evaporation is different because it can happen at any temperature - you can see this when wet clothes dry in the sun or even on a cool day, because water molecules can escape from the surface whenever they have enough energy. Some students confuse these processes and think boiling happens at any temperature because they see steam rising from warm water, but that''s actually evaporation, not boiling!' WHERE id = '90cc1732-04c7-4bc8-a66e-15c37137b3e7';
UPDATE questions SET explanation = 'A crescent moon looks like a thin, curved slice or banana shape, with only a small part of the moon lit up by the sun. Illustration B shows this characteristic crescent shape with just a small curved portion visible. Some other moon phases might look similar, but they show more of the moon''s surface lit up, making them fuller shapes like a half-circle or nearly full circle.' WHERE id = '7db3014a-4140-4433-a80a-4ad28808d0ca';
UPDATE questions SET explanation = 'Lead''s chemical symbol is Pb, which comes from its old Latin name "plumbum" – this is why many chemical symbols don''t match their English names! You might have thought it was Ld because that matches the English word "lead," but scientists use Latin names for many elements. Hg is actually mercury, and Cu is copper.' WHERE id = '12158786-918a-4f93-8752-9254eaff99bd';
UPDATE questions SET explanation = 'Washing soda, also known as sodium carbonate, is a strong alkali with a high pH that helps clean clothes by breaking down grease and removing stains effectively. It is definitely not an acid at all, so options A and C are wrong – acids and alkalis are complete opposites on the pH scale. While some cleaning products are weak alkalis, washing soda is particularly powerful, which is why it works so well at softening hard water and getting your clothes really clean.' WHERE id = 'e5c4ca2e-9e05-4608-a823-20a356462412';
UPDATE questions SET explanation = 'An element is a pure substance made of only one type of atom like iron, a compound is two or more elements chemically joined together like sodium chloride (salt), and a mixture is substances physically mixed together but not chemically joined like sand and sugar. Option B is incorrect because zinc and copper are both elements, not compounds – remember, compounds must have different elements bonded together! Option D wrongly classifies gold as a compound when it''s actually an element, while sodium chloride is a compound, not a mixture.' WHERE id = '082779cf-539b-4642-ab1f-e2f049f77d82';
UPDATE questions SET explanation = 'Heat energy can travel through empty space without needing any material to carry it, and this process is called radiation - just like how the Sun''s heat reaches Earth through space! Conduction and convection both need matter (solid, liquid, or gas) to transfer heat from one place to another, so they cannot work through empty space. The diagram must be showing radiation because it''s the only method that works without direct contact between objects or movement of particles.' WHERE id = 'db59d7df-ecdc-45a7-9e9f-e066814acc32';
UPDATE questions SET explanation = 'When Gaone pulls the object but it doesn''t move, it means the friction force pushing against her pull is stronger than her pulling force. If there were no forces against the object (option A) or if friction was zero (option D), the object would easily slide when she pulled it. Remember, for an object to stay still, the forces must be unbalanced with friction being the stronger force in this case.' WHERE id = '0a2f3108-2b5b-4701-bbf2-295568ea94da';
UPDATE questions SET explanation = 'Sulphuric acid is a strong acid because it is a powerful chemical that can cause serious burns and damage materials very quickly, which is why it''s used in car batteries and factories. Lemon juice, fruit juice, and vinegar are all weak acids that we can safely eat and drink because they only have a mild acidic effect on our tongues, making them taste sour but not dangerous to touch or taste.' WHERE id = '6a331bec-2a73-47ab-851a-0415bf039eec';
UPDATE questions SET explanation = 'Rubber tyres actually help vehicles move faster and smoother because they grip the road well and absorb bumps, making rides more comfortable. The size of a vehicle depends on how much space is needed inside for passengers or cargo, not on whether it has rubber tyres or not. Rubber tyres do cause vehicles to use slightly more fuel because of friction with the road, but this is much better than the old metal or wooden wheels that made travel very slow and uncomfortable.' WHERE id = '53800f91-a5a2-44d9-9bb8-852d9d705da7';
UPDATE questions SET explanation = 'A lower power rating means the electric kettle uses less electricity to do its job, which helps save energy and reduces the electricity bill. When we conserve electricity, we use only what we need and avoid wasting it, which is better for our homes and the environment. Power rating tells us how much electricity an appliance uses, not how well it works, so choosing a lower rating is about using less power, not improving it.' WHERE id = 'cff8e7d6-138f-480c-81ac-1b9b7384ff16';
UPDATE questions SET explanation = 'Metals are excellent conductors of heat, which means they allow heat to pass through them easily - this is why metal pots get hot quickly when cooking and why metal feels cold when you touch it (it conducts heat away from your hand). Materials like plastic, wood, and rubber are insulators that block or slow down heat from passing through, which is why we use them for pot handles and electrical wire coverings to protect us from heat and electricity.' WHERE id = 'dcd87994-e3f4-46bb-8f70-6bf03b2eee5a';
UPDATE questions SET explanation = 'Heat moves through gases mainly by convection, which happens when warm gas rises and cool gas sinks, creating a circular movement that carries heat from one place to another. While conduction does happen in gases, it works very poorly because gas particles are far apart and don''t bump into each other often enough to transfer much heat. This is why convection is the main way heat travels through air and other gases.' WHERE id = '9b88e045-f63a-4505-838b-e171f5dcf401';
UPDATE questions SET explanation = 'A compound is formed when atoms of different elements join together, like how water (H₂O) contains both hydrogen and oxygen atoms. A molecule of a compound can have many different kinds of elements combined in various amounts - for example, sugar has carbon, hydrogen, and oxygen atoms all bonded together. Remember that if a molecule has only one kind of element, like O₂ (oxygen gas), it''s not a compound but rather an element in molecular form.' WHERE id = '1f08ac9b-7ec0-40e0-84f8-071f79d5e608';
UPDATE questions SET explanation = 'A lunar eclipse happens when Earth moves between the Sun and the Moon, casting Earth''s shadow on the Moon. This can only occur during a full moon because that''s when the Moon is on the opposite side of Earth from the Sun, allowing Earth''s shadow to fall on it. During a new moon, the Moon is between Earth and the Sun, which is when a solar eclipse can happen instead.' WHERE id = 'f157aff9-9653-4cd9-9143-542138823532';
UPDATE questions SET explanation = 'A food chain shows the direction energy flows from one living thing to another, starting with a producer (like grass) and moving through consumers with arrows pointing toward the eater. Option A is correct because grass makes its own food, the grasshopper eats the grass, the frog eats the grasshopper, and the snake eats the frog—the arrows show who gets eaten by whom. Option D might look tempting, but the arrows point backwards, showing energy flowing the wrong way from predators back to their prey, which doesn''t happen in nature.' WHERE id = '3e72068a-8886-4e45-a4e5-1a642652855c';
UPDATE questions SET explanation = 'Water is considered soft when it is pure and does not have minerals like calcium and magnesium salts dissolved in it. Hard water is the opposite – it contains these dissolved salts, which is why soap doesn''t lather well in it and it causes scale to form in kettles and pipes. So remember, soft water is clean and free from these dissolved minerals, making it much better for washing and cleaning!' WHERE id = 'c6898036-8741-40a8-9180-4ba5fc708bef';
UPDATE questions SET explanation = 'Heat from the sun travels through the empty space between the sun and Earth, where there are no particles to bump into each other or carry the heat. This type of heat transfer is called radiation, which doesn''t need any material or air to travel through – it can move through empty space just like light does. Conduction and convection both need particles or materials to touch and transfer heat, which is why they cannot work in the empty space of outer space.' WHERE id = '6c19af33-baae-4537-a01c-aa2c7a924240';
UPDATE questions SET explanation = 'A population is a group of the same type of organism living together in the same area, so a group of birds in one place is called a population. An ecosystem would include not just the birds, but also other animals, plants, and non-living things like water and soil in that area. Remember, population means one type of organism, while community means different types of organisms living together.' WHERE id = 'e679bc72-5ef7-4c63-8952-fac08d76854b';
UPDATE questions SET explanation = 'When light hits a mirror, we call the incoming beam of light the incident ray - this is the scientific term for light traveling towards the mirror. The light ray that bounces back is called the reflected ray, not the refracted ray, because mirrors reflect light rather than bend it. Refraction only happens when light passes through different materials like water or glass, but mirrors bounce light back instead of letting it pass through.' WHERE id = '241db1ba-660d-4bb7-9954-45696779c6a9';
UPDATE questions SET explanation = 'Animals are called consumers because they cannot make their own food like plants do, so they must eat other living things to get energy. Plants are called producers because they can make their own food using sunlight, water, and air, but animals must consume (eat) plants or other animals to survive. Even though some animals only eat plants, they are still consumers because they depend on eating other organisms rather than producing food themselves.' WHERE id = '6d9ff91f-a400-475f-9101-f2595fc4100d';
UPDATE questions SET explanation = 'A hygrometer is the special instrument we use to measure humidity, which is the amount of water vapor (moisture) in the air - this is important for understanding weather conditions and how comfortable we feel. You might think a thermometer would measure humidity since wet air can feel different, but thermometers only measure temperature, not moisture in the air.' WHERE id = '57c692a7-0708-4e2e-88fd-0e366bbfb3ff';
UPDATE questions SET explanation = 'When electric charges flow or move from one place to another through a wire or conductor, we call this current electricity because the charges are flowing like a current in a river. Static electricity is different - it happens when charges build up and stay in one place without moving, like when you rub a balloon on your hair and it sticks to the wall. Think of current electricity as charges on the move, powering your torch or radio!' WHERE id = 'abd279fb-edbf-4c01-b080-1d8e5ae83cc7';
UPDATE questions SET explanation = 'Lightning is a powerful electrical discharge that carries tremendous energy, which can definitely damage buildings by causing fires, cracking walls, or destroying electrical systems when it strikes. This is why many buildings have lightning rods installed on their roofs – these metal rods actually do protect houses by safely directing the lightning''s electricity into the ground instead of letting it damage the structure. A wooden beam can easily catch fire if struck by lightning because wood burns when exposed to the intense heat produced by a lightning strike.' WHERE id = '1f88cac6-67c3-47a8-8f62-d300d21396ab';
UPDATE questions SET explanation = 'Alexander Graham Bell invented the telephone in 1876, which revolutionized how people communicate over long distances. You might have been tempted by option D, but Thomas Edison invented the light bulb and phonograph, not antibiotics—it was actually Alexander Fleming who discovered antibiotics like penicillin, though he''s incorrectly listed with pasteurisation in option A, which was Louis Pasteur''s invention.' WHERE id = '45d32469-76b0-425a-b889-57d7ef2a8d1d';
UPDATE questions SET explanation = 'Looking directly at the sun during a solar eclipse can seriously damage your eyes, so you need special protection that blocks harmful rays. Welding glasses are specially designed to protect eyes from extremely bright light and are safe for viewing eclipses, while regular sunglasses and even binoculars or telescopes without proper filters can still let in dangerous amounts of sunlight that will harm your eyes. Remember, never look at the sun through regular tools meant for normal viewing!' WHERE id = '779bb755-c6e2-4d8b-be2e-e98b8aa2836a';
UPDATE questions SET explanation = 'Transpiration is the process where water moves up through a plant and evaporates from the leaves into the air, which is exactly what the arrows are showing in the diagram. While evaporation also involves water turning into water vapour, it refers to water changing from surfaces like ponds or soil, not specifically the water loss from plants through their leaves. Think of transpiration as plants "breathing out" water vapour as they take in carbon dioxide for photosynthesis.' WHERE id = '3b923a0d-04fa-4f2b-878d-2bd1159c8d22';
UPDATE questions SET explanation = 'In our homes, we use parallel circuits because each electrical appliance can work independently - when one light bulb goes off, the others stay on, and each device gets the full voltage it needs to work properly. A series circuit would be a poor choice because if one appliance stops working or is switched off, all the others would stop too, just like old Christmas lights where one broken bulb makes the whole string go dark. Parallel wiring is safer and more practical for homes, which is why electricians always install it this way.' WHERE id = '096a7bb8-74db-40b7-ad0d-53f0b2a4d454';
UPDATE questions SET explanation = 'Morupule power station burns coal to produce heat, which is then used to generate electricity, making it a thermal power station. Even though Botswana has plenty of sunshine, Morupule doesn''t use solar panels – instead, it relies on our country''s coal deposits found near Palapye. The heat from burning coal creates steam that turns turbines to produce the electricity we use in our homes and schools.' WHERE id = '80cbc673-6779-454d-a70d-744af1226d4c';
UPDATE questions SET explanation = 'Iron nails need both water and oxygen from the air to rust, which is why the nail in water rusts because water contains dissolved oxygen. The nail in dry air might seem like it should rust since air has oxygen, but without moisture or water, rusting cannot happen. Greased nails and nails in oil are protected because the grease and oil form a barrier that keeps both water and oxygen away from the metal surface.' WHERE id = '06e003ec-c84e-42e4-9e5e-48ecfb06b56b';
UPDATE questions SET explanation = 'At point P, water from the ocean or lake is heated by the sun and changes from liquid water into water vapour (gas) that rises into the air - this process is called evaporation. While transpiration also adds water vapour to the air, it specifically happens when plants release water through their leaves, not when water evaporates directly from bodies of water like we see at P.' WHERE id = '1e30d854-3daa-4a07-ba94-fd449662ab97';
UPDATE questions SET explanation = 'Sound needs something to travel through, and it moves by making molecules vibrate and bump into each other, passing the sound energy along like dominoes falling. This is why sound cannot travel through a vacuum (empty space) where there are no molecules at all, and also why sound can actually travel through water – that''s how whales and dolphins communicate! Light is much faster than sound, which is why you see lightning before you hear the thunder.' WHERE id = 'ad73f9c5-a4c6-4a47-ad4d-e02fdf4adffe';
UPDATE questions SET explanation = 'When light travels from air into water, it bends or changes direction, and this bending is called refraction. This is why the stick appears bent at the point where it enters the water - the light rays coming from the underwater part of the stick bend as they leave the water and reach your eyes. Reflection is different because it happens when light bounces off surfaces like mirrors, but refraction is the bending that occurs when light passes through different materials.' WHERE id = '2d6e1b74-2b43-45e5-baed-4177276f75dc';
UPDATE questions SET explanation = 'Green plants use sunlight to make their own food through photosynthesis, and they store this energy as chemical energy in sugars like glucose. While the sun provides light energy and some heat is produced during the process, plants actually convert and store the energy in a chemical form that they can use later for growth and other life processes. This chemical energy is what we get when we eat plants or animals that have eaten plants!' WHERE id = '9fa4b018-3cec-4b87-b915-312bb912960c';
UPDATE questions SET explanation = 'Heat moves through materials when their particles touch and bump into each other, passing energy along. In gases, the particles are very far apart from each other, so they rarely collide and heat transfers very slowly. Solids like iron bars conduct heat much better because their particles are tightly packed together and constantly touching, making it easy for heat energy to pass from one particle to the next.' WHERE id = '19aaa340-6a65-434e-943a-8b14de12a29a';
UPDATE questions SET explanation = 'Pure water is neutral, which means it is neither an acid nor an alkali, so it will not change the colour of any litmus paper at all. Remember that only alkalis turn red litmus paper blue, while acids keep red litmus paper red and turn blue litmus paper red. Since pure water is neutral, it leaves both red and blue litmus paper unchanged.' WHERE id = '79667bd8-ace1-4ccb-978c-346aaa7d05fc';
UPDATE questions SET explanation = 'When a car slows down on a level road, friction between the tyres and the road surface works against the car''s movement, causing it to lose speed. This friction force opposes motion and is always present when two surfaces rub together. A weak wind from behind would actually help push the car forward rather than slow it down, and having no friction at all would mean the car couldn''t grip the road to stop or even move properly in the first place.' WHERE id = 'e40e0c04-5b99-4eb4-a639-a331f6511831';
UPDATE questions SET explanation = 'Sheet lightning is the bright flash you see lighting up the sky when lightning occurs between clouds or behind clouds, making the whole cloud appear to glow like a sheet of light. Some people think sheet lightning is silent, but it does make thunder – you just might not hear it because it happens so far away from where you are standing. This is different from fork lightning, which you can see as a jagged bolt traveling from a cloud down to the ground.' WHERE id = '6f267330-fe07-4ae0-9a25-064680e3a3ce';
UPDATE questions SET explanation = 'During a thunderstorm, lightning can send extremely powerful electrical surges through power lines and into your home, which can damage or destroy plugged-in equipment even if it''s switched off. The only way to truly protect your electric equipment is to completely disconnect it from the wall socket, because this breaks the path that the lightning''s electricity would travel. Simply switching equipment off still leaves it connected to the dangerous power surge that could come through the wires.' WHERE id = 'c6ecec4b-c2d1-4123-8445-241c31242ea2';
UPDATE questions SET explanation = 'When one oxygen atom joins with two hydrogen atoms, they form water (H₂O), which is a molecule of a compound because it contains two different types of atoms chemically bonded together. This is not a molecule of an element because elements contain only one type of atom, like O₂ (oxygen gas) or H₂ (hydrogen gas). It''s also not a mixture because the atoms are chemically joined, not just physically mixed together like sand and salt.' WHERE id = '2ae85fb7-113b-4310-ad15-480e248f4a62';
UPDATE questions SET explanation = 'When an object completely blocks light from passing through it, we call that object opaque. Materials like wood, metal, and thick cardboard are opaque because no light can travel through them at all. Transparent objects like clear glass would let light pass straight through, while translucent objects like frosted glass would let some light through but make things look blurry.' WHERE id = '2ade2b97-457a-4681-8c79-2d6005cce4a6';
UPDATE questions SET explanation = 'When light travels from water into air, it bends and changes direction, making the pencil appear broken or bent at the water''s surface – this bending of light is called refraction. Reflection is different because it happens when light bounces off a surface like a mirror, showing you an image of something, but here the pencil itself looks bent because light is passing through the water and bending. This is why objects underwater always look like they''re in a different position than they really are!' WHERE id = '28c32808-1905-4837-96e7-9e49f74f4d8e';
UPDATE questions SET explanation = 'Acids have a sour taste, which you can notice in foods like lemons, oranges, and vinegar - they all make your mouth pucker! Sweet tastes come from sugars, not acids, while bitter tastes are usually found in alkaline substances like baking soda or very strong tea. Remember though, you should never taste chemicals in the laboratory to test if they are acids - we use special indicator papers for that instead!' WHERE id = '07ab530a-e487-4fb3-b537-5f98910058d5';
UPDATE questions SET explanation = 'Energy conservation means that energy always stays the same amount in total – it cannot be created from nothing or destroyed completely, but it can change from one form to another, like when electrical energy becomes light and heat in a bulb. Option A describes what energy is, not how it is conserved, while options C and D are wrong because energy can never be created or destroyed at all. This principle helps us understand that energy is always transformed, never lost, which is why we can trace where energy goes in any system.' WHERE id = '850b4c8a-ef0b-4a6c-b829-15c0ac25f2d5';
UPDATE questions SET explanation = 'Strong acids like hydrochloric acid and sulphuric acid break apart completely in water to release lots of hydrogen ions, making them very powerful and dangerous, while weak acids like tartaric acid (found in grapes) and vinegar only release some hydrogen ions, making them gentler and safer to handle. You might be confused by option C because both sulphuric acid and nitric acid are actually strong acids, not weak ones, so they cannot be matched together as opposites. Remember that common household acids like vinegar and citric acid are usually weak, while laboratory acids with "hydro-" or "-ic" names like hydrochloric and sulphuric are typically strong.' WHERE id = '393e92dc-f5e6-4cdd-99f8-b958fa6e5ea7';
UPDATE questions SET explanation = 'Blue litmus paper is a special indicator that changes color to show us whether a substance is an acid or a base. When you dip blue litmus paper into an acid, it always turns red because acids have a special property that makes blue litmus change to red. If the litmus paper stays blue, that tells you the substance is not an acid—it''s either a base or neutral like water.' WHERE id = '8371d13a-d6e9-454f-a254-02f4b0be8005';
UPDATE questions SET explanation = 'Baboons are common animals in Botswana and are not on the protected species list, which means they can be hunted with proper permits. Rhinos, cheetahs, and kori bustards are all protected by law because their numbers are low and they are at risk of disappearing from our country. The government protects these special animals to make sure future generations can still see them in Botswana.' WHERE id = 'dbe7edcc-d0ac-464f-9f0f-9f11ad0fe8ff';
UPDATE questions SET explanation = 'A saturated solution is one that has dissolved as much solute as it possibly can at that temperature - if you try to add more solute, it will just sink to the bottom without dissolving. Think of it like a sponge full of water that cannot absorb even one more drop! Options B and C might sound correct because we sometimes use "strong" and "weak" to describe solutions, but these words actually refer to concentration (how much solute is dissolved), not whether the solution can still dissolve more.' WHERE id = 'ed494996-d33e-405a-bbcb-29dfe1795424';
UPDATE questions SET explanation = 'When you boil hard water, the heat causes the dissolved minerals (like calcium) to form a solid coating on the pot, which removes them from the water and makes it softer. Using more or less soap doesn''t change the minerals in the water - it only changes how much soap you''re wasting, since hard water makes it difficult for soap to lather properly. Remember, softening water means removing the minerals that make it hard, not just using different amounts of water or soap!' WHERE id = '1f0dc6e1-1baf-46ba-bda5-f21a7cd52e91';
UPDATE questions SET explanation = 'Making clay pots is a traditional scientific practice in Botswana because it involves understanding natural materials like clay soil, knowing the right temperature for firing, and applying skills that have been passed down through generations in our culture. This is real science that our ancestors used every day! Making metal pots requires different technology that wasn''t traditionally available in Botswana, while making cake and tea are cooking activities rather than traditional scientific practices.' WHERE id = 'e97d4f42-e476-4afc-aaea-7f3bc16ab9e1';
UPDATE questions SET explanation = 'To separate sand and salt, you first dissolve the salt in water so it mixes completely while the sand doesn''t dissolve. Then you use filtration to pour the mixture through a filter paper, which traps the sand particles but lets the salty water pass through. While dissolving is an important first step, filtration is the actual separation method that removes the sand from the mixture.' WHERE id = 'd07f8377-926b-439a-a1db-8436276d8a69';
UPDATE questions SET explanation = 'Iron is a magnetic material, which means it is attracted to magnets, while soil is not magnetic. When you hold a magnet near the mixture, the iron fillings will stick to the magnet and separate from the soil easily. Sieving might seem like it could work, but iron fillings and soil particles are often similar in size, so they would pass through the sieve holes together instead of separating.' WHERE id = '0ba70af5-3009-403b-9b8e-b3e024a59b48';
UPDATE questions SET explanation = 'Lead is a heavy metal element that has been used for thousands of years, and scientists use the symbol Pb because it comes from lead''s Latin name "plumbum" (which is also why people who fix water pipes are called plumbers!). You might think copper should be C, but copper''s symbol is actually Cu (from its Latin name "cuprum"), while C is the symbol for carbon, and the other symbols Au and Zn belong to gold and zinc respectively.' WHERE id = 'e788b637-efb6-474c-b1e8-9126f1978f47';
UPDATE questions SET explanation = 'When you play a radio using a battery, the chemicals inside the battery store energy that gets converted into electrical energy, which then powers the radio''s speaker to produce sound energy. This is why the answer is chemical energy to sound energy – the battery''s stored chemical energy ends up as the sound you hear from the radio. Light energy would only be correct if the battery was powering something that produces light, like a torch or bulb, not a radio that makes sound.' WHERE id = 'be2986a3-653c-4ecb-a6a2-1124e0586c8b';
UPDATE questions SET explanation = 'Heat from the sun travels through empty space to reach Earth by radiation, which is the only way energy can move through a vacuum where there is no air or matter. Convection and conduction both need materials like air or solid objects to transfer heat, but space between the sun and Earth is empty, so these methods cannot work. Radiation allows the sun''s energy to travel as invisible waves that warm our planet when they arrive.' WHERE id = '832d3159-4f54-4a2e-8d02-c1b6608cbf95';
UPDATE questions SET explanation = 'Radiation is the only way heat can travel through a vacuum because it moves as waves that don''t need any material to pass through, just like how the Sun''s heat reaches Earth through empty space. Conduction and convection both need particles of matter (like air or water) to transfer heat, so they cannot work in a vacuum where there is nothing at all.' WHERE id = '2fd4faad-738b-4620-a82b-36f9b3b23e59';
UPDATE questions SET explanation = 'Weather describes what''s happening in the atmosphere right now or over a few days, like if it''s hot and sunny today in Gaborone. Climate, on the other hand, is the pattern of weather we expect in a place when we look at many years of information – for example, we know Botswana generally has a hot, dry climate because that''s what the weather has been like here over many, many years. Think of it this way: weather is what you wear today, but climate is what types of clothes you keep in your wardrobe all year long.' WHERE id = 'f0e60a86-addb-40b6-9b2a-a5ba8e01a6e6';
UPDATE questions SET explanation = 'Plants use sunlight to make their own food through photosynthesis, and they store this energy as chemical energy in substances like glucose (sugar). This chemical energy is what keeps the plant alive and growing, and it''s also the energy we get when we eat plants or animals that ate plants. While plants might feel warm in the sun, they don''t convert light into heat energy as their main purpose – they convert it into chemical energy that can be stored and used later.' WHERE id = 'd657877d-2072-4db9-a471-73f65f53e9b2';
UPDATE questions SET explanation = 'Solids are the best conductors of heat because their particles are tightly packed together, allowing heat energy to pass quickly from one particle to the next, like when a metal spoon gets hot in tea. While liquids and gases can also transfer heat, they do so much more slowly because their particles are farther apart and move around more freely. Light is not a state of matter at all, so it doesn''t conduct heat the same way materials do.' WHERE id = '111f7900-7d01-4d44-912a-2ed0896c0994';
UPDATE questions SET explanation = 'A population is made up of living things that are all the same kind - like a group of zebras in the savanna or a stand of mopane trees growing together. The key is that they must all be the same species, not different types of animals or plants mixed together. Option D describes a habitat, which is where populations live, but not what a population actually is.' WHERE id = '7995bc29-2fe9-4d37-b1f1-8db7cca5fcb8';
UPDATE questions SET explanation = 'A full moon occurs when the entire face of the moon that we see from Earth is lit up by the Sun, appearing as a complete bright circle in the sky. Phase B shows this perfect round, fully illuminated moon. Some other phases might show the moon partly lit, like a crescent or half-circle, but only when the whole face is bright do we call it a full moon.' WHERE id = 'b77e7d8e-2291-4263-8dfe-d39309dc5684';
UPDATE questions SET explanation = 'A hurricane is a powerful, spinning storm system that develops when warm ocean water heats the air above it, creating a low pressure area where winds begin rotating in a massive circle. While option A mentions wind and low pressure over the ocean, it''s incomplete because a hurricane is much more than just wind—it''s an entire severe storm system with heavy rain, thunder, and dangerous winds all rotating together. Think of it like a giant spinning wheel of bad weather that can be hundreds of kilometres wide!' WHERE id = '43c2257d-44da-44f5-8f04-0543d2287b29';
UPDATE questions SET explanation = 'A front in weather happens when two different air masses meet each other - for example, when warm air meets cold air. Think of it like two different types of air trying to push against each other at a boundary line, just like when you see clouds forming in a line across the sky. While option B might seem close, the air masses don''t actually combine or mix together - they stay separate and push against each other at the boundary, which is why we get changes in weather at fronts.' WHERE id = 'eab67b31-0188-4048-a66e-47af22d7d8c6';
UPDATE questions SET explanation = 'When hot air rises from the road surface on a very hot day, light rays bend as they pass through layers of air at different temperatures, creating what we call refraction of light - this makes Mr Morake see a mirage that looks like water on the road ahead. While reflection of light involves light bouncing off surfaces like mirrors, what causes this mirage is actually light bending through the hot air, not bouncing off anything. This is why the "water" disappears as you get closer to it!' WHERE id = 'd1fbe403-3177-42b0-83be-0f6968a91af2';
UPDATE questions SET explanation = 'A food chain is a simple diagram that shows how energy and food passes from one living thing to another in a straight line, like grass → zebra → lion. A food web is different because it shows many connected food chains with arrows going in different directions, showing that animals often eat more than one type of food. Since this diagram shows just one pathway of who eats whom, it is a food chain.' WHERE id = 'f4a05296-a480-4d2a-b8f0-fd4f70e0b795';
UPDATE questions SET explanation = 'In a second class lever, the load is always positioned between the pivot (fulcrum) and the effort, which makes it easier to lift heavy things - think of a wheelbarrow where the wheel is the pivot, the load sits in the middle, and you lift the handles with effort. Option A describes a first class lever like a seesaw, where the pivot is in the middle instead. This arrangement in second class levers gives you a mechanical advantage, meaning you can lift heavy loads with less effort!' WHERE id = 'f08b2d83-f0f3-4ff5-9b55-b550b64f2b05';
UPDATE questions SET explanation = 'A switch is the component in a circuit that can open or close to control whether electricity flows through the circuit, just like a light switch on your wall at home. In the diagram, A is the switch because it shows the part that can be turned on or off to complete or break the electrical path. The other components (B, C, and D) are different parts of the circuit like the battery, bulb, or wires that serve other purposes.' WHERE id = 'a5c2c4b9-1ea1-4205-ade1-fe28127e6cfe';
UPDATE questions SET explanation = 'Lightning follows the easiest path to the ground, so it strikes the tallest objects first, making tall trees very dangerous because you could be struck if you stand under them. Inside a house or car, you are protected because the electricity travels around the outside of these structures, and even a hole in the ground is safer because you are lower than your surroundings where lightning might strike.' WHERE id = '30c2f89d-5b40-43c9-be6d-1366de68caea';
UPDATE questions SET explanation = 'The pivot is the point where the two blades of the scissors are joined together by a screw or bolt, allowing them to move around that fixed point. In these scissors, point O is where the two blades are connected and rotate, making it the pivot or fulcrum. Point P might look important because it''s where you apply force with your fingers, but remember the pivot must be the fixed turning point, not where you push.' WHERE id = '9627e882-6a31-4cd1-a2a3-e1958c62382f';
UPDATE questions SET explanation = 'During a thunderstorm, lightning can send powerful electrical surges through the wires in your home, which can damage any equipment that''s plugged in. Disconnecting equipment completely (unplugging it from the wall) breaks the path between the dangerous lightning surge and your device, keeping it safe. Simply switching equipment off isn''t enough protection because electricity from lightning can still travel through the plugged-in cord and damage the equipment even when it''s turned off.' WHERE id = '3275ede0-aba1-4f3e-82a8-9764a610a050';
UPDATE questions SET explanation = 'When you rub two sticks together very quickly, friction creates heat between them, and this heat can eventually start a fire - this is how our ancestors made fire for thousands of years! Pressure alone won''t create the heat needed for fire because you need the rubbing motion that friction provides. You can try this yourself by rubbing your hands together quickly - notice how they get warm from friction!' WHERE id = '172804bb-a734-4ccb-8645-5c5e0f20a981';
UPDATE questions SET explanation = 'When you drop a magnet from a height, the hard impact can shake up the tiny magnetic particles inside it, causing them to lose their organized arrangement and making the magnet weaker or non-magnetic. The other options about keeping magnets separated or in containers are actually good storage practices that help preserve magnetism, not destroy it. Physical shock from dropping, heating magnets very hot, or hitting them with a hammer are the main ways magnets lose their magnetic power.' WHERE id = '61fcd2a8-54a1-4fa3-8947-9e80aa3b4971';
UPDATE questions SET explanation = 'Rollers reduce friction because they change sliding motion into rolling motion, which creates much less resistance between surfaces – think of how much easier it is to move heavy furniture on wheels than to drag it across the floor! Dragging, pushing, and rubbing all create more friction because they involve surfaces sliding directly against each other, which makes movement harder and requires more force.' WHERE id = 'cb48b64d-000c-49cc-a91e-a8159a8836e2';
UPDATE questions SET explanation = 'Streamlined objects have smooth, curved shapes that help them move easily through air or water by reducing friction and air resistance. Aeroplanes, fish, and kites all have these special curved shapes that let them glide smoothly, but a monkey has a rough, bumpy body shape with arms and legs sticking out that create lots of resistance when moving. That''s why engineers copy streamlined shapes from nature when designing fast-moving vehicles!' WHERE id = 'b848d963-9f0b-427f-8a2c-61efa735c4dd';
UPDATE questions SET explanation = 'Strong acids like hydrochloric acid, nitric acid, and sulphuric acid completely break apart in water and are very powerful, which is why they are commonly used in laboratories and industries. Tartaric acid is a weak acid found naturally in fruits like grapes and tamarinds - it doesn''t break apart completely in water, making it safe enough to be used in foods and drinks. Remember, weak acids are still acids with a sour taste and can turn blue litmus paper red, but they are much gentler than strong acids.' WHERE id = '694264c4-784d-43c6-b262-7ff145a07ee9';
UPDATE questions SET explanation = 'When Metsi heats the water in the pot, the hot water moves around in currents, carrying heat to the bowl or dish sitting in it - this moving of heat through liquids is called convection. You might think it''s conduction because the bowl touches the water, but conduction only works when objects directly touch each other without any movement, while here the water itself is moving and transferring the heat as it flows around the bowl.' WHERE id = 'f9cfe089-9280-4a4e-9658-03f4a210c190';
UPDATE questions SET explanation = 'Lightning is attracted to metal objects and tall things that stick up high, so wearing rubber boots actually protects you during a storm because rubber does not conduct electricity well. Standing under tall trees is very dangerous because lightning often strikes the tallest objects, and walking barefoot or touching metal wires puts you at risk since your body can become a path for the electrical current to reach the ground.' WHERE id = '52d9d25e-afdb-4c2d-97a2-23480bed87d7';
UPDATE questions SET explanation = 'Science is for everyone, no matter if you are a boy or a girl! Both males and females can become doctors, engineers, botanists, chemists, or any other science professional they choose. While some people wrongly believe that only boys should do science careers, the truth is that girls and boys are equally capable of succeeding in any science field they work hard to pursue.' WHERE id = '4559b941-8af8-46dc-9d0e-2f6a616d5df7';
UPDATE questions SET explanation = 'Sound travels fastest through solids because the particles are very close together and tightly packed, allowing sound vibrations to pass quickly from one particle to the next. In gases like air, the particles are far apart, so sound moves much slower as it has to jump bigger gaps between particles. Sound cannot travel at all through a vacuum because there are no particles to carry the vibrations.' WHERE id = '628497f4-fee8-448f-85df-eda34a46052e';
UPDATE questions SET explanation = 'In a second class lever, the effort is at one end, the pivot (fulcrum) is at the other end, and the load sits between them, like when you use a wheelbarrow where you lift the handles (effort) while the wheel acts as the pivot and the load is in the middle. A first class lever is different because the pivot is in the middle, with the effort and load on opposite ends, like a seesaw. Remember the order for second class levers: Pivot-Load-Effort, which makes it easier to lift heavy things!' WHERE id = 'a2449337-514f-4072-8719-78724a76e7de';
UPDATE questions SET explanation = 'When two surfaces rub against each other, like when you push a book across your desk, friction force is created that tries to slow down or stop the movement. This is different from magnetic force, which only works between magnets and certain metals without needing to touch, or gravitational force, which pulls objects toward Earth. Friction is the special force that always appears when surfaces are in contact and moving against each other.' WHERE id = '14c5c183-451e-4764-a6f8-69c3594aa234';
UPDATE questions SET explanation = 'Alkaline substances have a bitter taste, which is one of their special properties that helps us identify them - think about the bitter taste of soap if you''ve ever accidentally gotten it in your mouth! This is very different from acids, which have a sour taste like lemons or vinegar. Remember though, we should never taste chemicals in science class to identify them because many can be dangerous!' WHERE id = 'fcf7f4af-fcb0-4946-bfdb-22b4ecb89f57';
UPDATE questions SET explanation = 'A habitat is the specific place where an organism lives and finds everything it needs to survive, like food, water, and shelter. For example, a mopane worm''s habitat is a mopane tree, and a lion''s habitat is the grassland. An ecosystem is different because it includes the habitat plus all the living things and how they interact with each other in that area.' WHERE id = '929eef24-99f0-4a24-a4c4-247ad72c6731';
UPDATE questions SET explanation = 'In our homes, we use parallel circuits because each electrical appliance gets its own separate path to the power source, so if one device stops working or is switched off, all the others keep running normally. This is much better than a series circuit, where all devices share one path and switching off one device would turn off everything in your home – imagine your TV going off every time someone turns off a light! Parallel wiring also means each appliance gets the full voltage it needs to work properly.' WHERE id = '3cbb2c24-58ed-4a6f-9fcd-d6eabc79bdd6';
UPDATE questions SET explanation = 'Looking directly at the sun during a solar eclipse can permanently damage your eyes, so you need very strong protection like welding glasses, which are specially designed to block harmful sun rays. Regular sunglasses might seem safe because they make things darker, but they don''t block enough of the dangerous rays that can burn your eyes. Binoculars and telescopes would actually make it worse by magnifying the sun''s harmful rays directly into your eyes!' WHERE id = 'acc91833-335f-4d39-bf1f-5c2d7dcf0e1a';
UPDATE questions SET explanation = 'Morupule power station burns coal to produce heat, which creates steam to turn turbines and generate electricity – this is called thermal energy. While hydroelectric power stations use water from dams to make electricity, Morupule uses coal because Botswana has large coal deposits near Palapye but doesn''t have big rivers with enough water flow for hydroelectric dams. The heat from burning coal is what makes Morupule a thermal power station.' WHERE id = '1144b9c8-ab0b-46ad-9f5c-f5e3b306c3e8';
UPDATE questions SET explanation = 'Substances that turn red litmus paper blue are alkaline (also called bases), because alkaline substances have this special property of changing the colour of litmus paper from red to blue. Acids do the opposite – they turn blue litmus paper red, which is how we can tell them apart. Remember this simple rule: alkaline substances make red litmus go blue, while acids make blue litmus go red!' WHERE id = '454f3d53-23ce-47be-aede-66c91b2a0c98';
UPDATE questions SET explanation = 'When sugar can no longer dissolve in tea even after stirring, the solution has become saturated, which means the tea is holding as much sugar as it possibly can at that temperature. The sugar did dissolve at first, but once the solution reached its limit, the extra sugar remained at the bottom as solid crystals. A saturated solution is full and cannot accept any more solute.' WHERE id = '44018cbc-c809-4857-8637-ace7106501fc';
UPDATE questions SET explanation = 'A mirage is an optical illusion that happens when hot air near the road surface bends light rays, making it look like there''s water ahead that disappears as you get closer. This is different from refraction, which is the scientific name for light bending, but we use the special word "mirage" to describe this particular desert or hot road illusion. You might have seen this effect on very hot days on the roads around Botswana!' WHERE id = '7e651546-187a-4e85-b427-6840fe4d2451';
UPDATE questions SET explanation = 'Amphibians are cold-blooded animals that must lay their eggs in water because their eggs have no hard shell and would dry out on land. Animals like frogs, toads, and salamanders are amphibians that start their lives in water as tadpoles before growing legs and moving onto land. Although reptiles like crocodiles and turtles are also cold-blooded and some lay eggs near water, they lay their eggs on land, not in the water itself.' WHERE id = 'c8b93610-1c49-4d91-b656-1a2da073feda';
UPDATE questions SET explanation = 'Lightning happens when static electricity builds up in clouds and suddenly jumps between the clouds and the ground, creating a bright flash of light and heat. This is different from current electricity that flows steadily through wires in your home to power lights and appliances. The huge spark you see during a thunderstorm is nature''s way of releasing the static charge that has built up, just like the small shock you might feel when touching a metal door handle after walking on a carpet.' WHERE id = 'd78a29c4-491b-4621-9bfc-d9b28111d060';
UPDATE questions SET explanation = 'Friction happens when surfaces rub together, and we can reduce it by making surfaces smoother or separating them. Increasing roughness does the opposite – it makes surfaces grip more and creates MORE friction, like how rough sandpaper creates more resistance than smooth paper. Ball bearings, oiling, and streamlining all work to reduce friction by making movement smoother and easier.' WHERE id = '64bbd50b-e821-4aab-b4f1-096b7f38d4e9';
UPDATE questions SET explanation = 'Refraction happens when light moves from one material to another, like from air into water, and the light ray bends or changes direction. You might have noticed this when a straw in a glass of water looks bent or broken at the surface. Option A describes reflection, which is different because that''s when light bounces back off a surface like a mirror, rather than bending as it passes through.' WHERE id = '5d23939a-4a16-49bf-b000-fa438708dc40';
UPDATE questions SET explanation = 'Acidic substances have a sour taste, which is why lemons, vinegar, and sour milk all taste sharp or tangy - they contain acids! While some acids can be corrosive (able to wear away materials), not all acids are strongly corrosive, so this is not their main identifying property. Remember, substances that feel soapy are actually the opposite of acids - they are alkalis or bases!' WHERE id = 'ed181cfd-e9cc-4514-a7e4-ada47d64fb4d';
UPDATE questions SET explanation = 'Parallel circuits are preferred in buildings because each appliance has its own separate path for electricity to flow. This means if one light bulb breaks or one appliance stops working, all the other lights and appliances keep working normally. In a series circuit (which would make option B true), if one device breaks, everything stops working - imagine if your entire house went dark just because one bulb broke!' WHERE id = '3c9cd301-4a90-4d78-8343-2f4edf4ee698';
UPDATE questions SET explanation = 'Animals breathe in oxygen from the air because their bodies need it to release energy from food in a process called respiration. When animals breathe out, they release carbon dioxide, which is the waste gas produced during respiration - so carbon dioxide goes OUT of the body, not IN. Although nitrogen makes up most of the air we breathe in, our bodies don''t actually use it the way they use oxygen.' WHERE id = '695bf926-cadc-4891-8384-a8be2d5f73c9';
UPDATE questions SET explanation = 'An ecosystem is like a natural community that includes both living things (like plants, animals, and insects) and non-living things (like water, soil, air, and sunlight) all working together. All these parts depend on one another – for example, plants need sunlight and water to grow, and animals need plants for food. So an ecosystem cannot contain only living things or only non-living things, because both are needed for life to survive.' WHERE id = '90fed457-82d7-4fba-b5a0-82f859d5d502';
UPDATE questions SET explanation = 'When you can see clearly through an object, like looking through a clean window or a glass of water, that object is transparent because it lets light pass straight through without blocking your view. Translucent objects might seem similar, but they only let some light through in a blurry way, like frosted glass or wax paper, so you cannot see clearly through them. Opaque objects like wood or metal block all light completely, so you cannot see through them at all.' WHERE id = '6bd2b3fe-35b8-4c1e-b761-d4d111dbd3bd';
UPDATE questions SET explanation = 'Materials that do not allow electricity to flow through them are called insulators because they block or insulate against the movement of electrical current. Conductors are the opposite – they are materials like metals that do allow electricity to pass through them easily. Wood and nails are just examples of materials, where wood is an insulator and a nail (being metal) is a conductor.' WHERE id = '6a7dfb2a-8967-4884-8b36-1b73be5ce740';
UPDATE questions SET explanation = 'A hygrometer is the special instrument we use to measure humidity, which tells us how much water vapor is in the air around us. You might confuse it with a thermometer, but remember that a thermometer only measures temperature (how hot or cold it is), not the moisture in the air. A barometer measures air pressure, while a rain gauge collects and measures rainfall that has already fallen from the sky.' WHERE id = '7fa9448a-3231-46d8-b505-aa41e5e34e60';
UPDATE questions SET explanation = 'National Parks and Game Reserves are traditional ways that Botswana and other countries have used for many years to protect animals by setting aside special protected areas where wildlife can live safely. While hunting seasons, conservation laws, and education are all modern methods of animal conservation, they came later as new approaches to help protect our wildlife. Setting aside land as protected areas for animals was one of the very first methods our ancestors used to make sure wildlife would survive for future generations.' WHERE id = 'f0f3929d-d6fd-4220-b299-35f742fedf31';
UPDATE questions SET explanation = 'When a gas cools down and changes into a liquid, we call this process condensation – think of water droplets forming on the outside of a cold drink bottle on a hot day. Freezing might seem correct, but that''s when a liquid turns into a solid (like water becoming ice), not when a gas turns into a liquid. The letter S represents condensation because it shows the change from gas to liquid state.' WHERE id = '038495fb-32d0-443d-9869-f05d5618a2e4';
UPDATE questions SET explanation = 'Conservation means actively protecting and managing our environment, but it doesn''t mean the environment is never damaged - some harm can still occur even with conservation efforts. The real benefits of conservation include protecting rare animals like our rhinos and wild dogs, helping plants absorb carbon dioxide to keep air clean, and ensuring that future generations of Batswana can enjoy our beautiful natural resources like the Okavango Delta.' WHERE id = '70a5cfc2-8979-4942-98cd-6cf192421d3a';
UPDATE questions SET explanation = 'During a full moon, the Sun lights up the entire side of the Moon facing Earth, so we see the whole Moon looking bright and round in the night sky. You might think half the Moon is dark because sometimes we do see half-moon shapes, but that happens during different phases when the Moon is in other positions—not during a full moon. The Moon is always brightest at night when it''s full, not in the afternoon when the Sun is still shining brightly.' WHERE id = 'a1f6d40c-4be8-4e81-9d65-cecd420f5d32';
UPDATE questions SET explanation = 'Lead is the element represented by the symbol Pb, which comes from its Latin name "plumbum." This is why some elements have symbols that don''t match their English names. Phosphorus might seem like a good choice because it starts with "P," but its symbol is actually just P, not Pb.' WHERE id = '7bd41d06-0b63-43f7-a95b-f45c0106752d';
UPDATE questions SET explanation = 'Looking at weather symbols, snow is the one that is NOT matched correctly with its description in this question. Snow has a specific symbol (usually shown as snowflakes *), which is different from other weather symbols like clouds, wind arrows, or lightning bolts. The other options like very cloudy, storm wind, and thunderstorm all have distinct symbols that match their weather conditions correctly.' WHERE id = 'f9c8c763-c57c-4bcb-93df-fa09cbfa4e29';
UPDATE questions SET explanation = 'Living things and soil work together in an important cycle - plants grow in soil and get nutrients from it, then people and animals eat those plants (or eat other animals that ate plants) to survive. This means we all depend on soil even though we don''t eat it directly, just like how animals depend on it through the food chain. Soil isn''t killed by living things; instead, it stays healthy when dead plants and animals break down and return nutrients back to it.' WHERE id = '9dfa8377-7c43-486a-8758-c55926d82da5';
UPDATE questions SET explanation = 'Carbon is a pure chemical element because it is made up of only one type of atom and cannot be broken down into simpler substances. Carbon dioxide, water, and table salt are all compounds, which means they are made by combining two or more different elements together chemically. You can remember this by noticing that compounds have names that suggest they contain more than one element, like carbon di-oxide (carbon + oxygen) or H₂O for water (hydrogen + oxygen).' WHERE id = '7c04b390-aadf-409c-a188-4dbe4a84ee7d';
UPDATE questions SET explanation = 'When you add salt to water, the salt particles get in the way of the water molecules trying to escape as steam, so the water needs to get hotter before it can boil. This means the boiling point increases above the normal 100°C. Some students might think the boiling point stays the same because pure water always boils at 100°C, but adding salt changes this by making the water impure.' WHERE id = 'a0148045-ed7a-46cb-a654-5a911f1239ce';
UPDATE questions SET explanation = 'When a substance dissolves in water, it breaks down into tiny particles that we cannot see anymore, like the sugar did. Iron filings do not dissolve in water, so they stay visible at the bottom of the container – we call this property insoluble. Some students might confuse this with soluble (option B), but soluble means the opposite – it describes substances that DO dissolve and disappear in water, like sugar or salt.' WHERE id = '625f8841-114d-4772-a193-5a7834d1b4fc';
UPDATE questions SET explanation = 'Producers are organisms that make their own food from sunlight through photosynthesis, and maize is a green plant that does exactly this. Chickens, snakes, and vultures are all consumers because they must eat other organisms to get energy - they cannot make their own food like plants can. Remember, in any food web, only plants and other photosynthetic organisms can be producers.' WHERE id = '71e71107-1bf8-4756-89c3-b7b71db51b80';
UPDATE questions SET explanation = 'Hot water makes substances dissolve faster because the heat gives the water molecules more energy to move around quickly and break apart the particles of the substance you''re dissolving. Cold water works too, but much more slowly since the water molecules move less energetically. Think about how quickly sugar dissolves in your hot tea compared to a cold drink!' WHERE id = 'e77f087a-3737-4cea-9619-1ad843e01eae';
UPDATE questions SET explanation = 'The invention of the wheel helped transport develop by making vehicles faster, more comfortable, easier to control, and quieter with rubber wheels. Option B is incorrect because vehicles today actually travel at very high speeds, not low speeds – this is one of the great benefits the wheel brought to transport! All the other options correctly explain how the wheel improved our transport systems over time.' WHERE id = '38cfbb36-eccc-4be4-998d-96a7e7f3002d';
UPDATE questions SET explanation = 'A lunar eclipse happens only during a full moon because that''s when the Earth moves directly between the Sun and the Moon, casting Earth''s shadow on the Moon. The Moon must be on the opposite side of Earth from the Sun for this alignment to work, which is exactly what a full moon is. While you might think an eclipse could happen during any moon phase, the three objects need this special straight-line arrangement for Earth''s shadow to fall on the Moon.' WHERE id = 'afec02af-6a63-4924-bd38-7b6b82854cad';
UPDATE questions SET explanation = 'During a lunar eclipse, the Earth must be directly between the Sun and the Moon, blocking sunlight from reaching the Moon''s surface. Looking at position S, you can see the Earth is perfectly lined up between the Sun and Moon, which is exactly what creates a lunar eclipse. Position Q might look tempting because the Moon is between the Sun and Earth, but that arrangement actually creates a solar eclipse, not a lunar eclipse.' WHERE id = '08c9acc6-86b6-4d4a-81d8-370b9c4e4c7b';
UPDATE questions SET explanation = 'Sea water contains high amounts of dissolved salts and minerals like calcium and magnesium, which make it hard water that does not form lather easily with soap. Rain water, river water, and distilled water are all soft water types with very few dissolved minerals, so they form lather quickly and easily when soap is added.' WHERE id = '1c9b3488-51ec-4648-a805-0a057bdc80b2';
UPDATE questions SET explanation = 'A population is a group of living things that are all the same species living together in one area, like a group of impala in the Okavango Delta or a group of mopane trees in your village. It''s important to remember that a population must be the same species - not different species mixed together. When you have different species living together in the same area, that is called a community, not a population.' WHERE id = '7394b334-3820-4933-b644-326919c7a75f';
UPDATE questions SET explanation = 'Global warming is an effect of pollution on the environment because when harmful gases from factories, cars, and burning waste go into the air, they trap heat around the Earth and make our planet warmer. While pollution can also cause eye problems and breathing problems in people, these are effects on human health, not on the environment itself. The question asks specifically about effects on the environment, which includes things like climate, oceans, forests, and wildlife.' WHERE id = 'd420ca08-0aab-4d7e-b588-f86170c8ebea';
UPDATE questions SET explanation = 'Thomas Edison was a famous American inventor who created the first practical electric light bulb in 1879, which changed how people could light their homes and work at night. While Alexander Graham Bell invented the telephone, Edison''s light bulb was his most important contribution to science because it brought electricity into everyday life for millions of people around the world. His invention helped make modern life possible by allowing us to have light whenever we need it, not just during daytime.' WHERE id = 'd6e5596d-745c-4d2a-bec1-8830f7e64f2c';
UPDATE questions SET explanation = 'Water pollution happens when harmful substances get directly into water bodies like rivers, dams, and streams, making the water dirty and unsafe for drinking or for animals. When you throw waste directly into water, it pollutes the water immediately, but throwing waste on land (option D) causes land pollution instead, even though some of that waste might eventually wash into water during rains. Playing loud radios and releasing gases into the air cause noise pollution and air pollution, not water pollution.' WHERE id = '606643fe-a64d-45d5-b0ad-07e9aa72ec8f';
UPDATE questions SET explanation = 'A warm front forms when a mass of warm air moves forward and pushes up over cooler air, replacing the cold air that was there before. Option D might seem correct, but that describes a cold front, which is the opposite situation where cold air pushes under and replaces warm air. Think of it this way: the type of front is named after which air mass is advancing or taking over the area.' WHERE id = '5eb83c1b-cc21-48ed-9a2f-86b64784ce44';
UPDATE questions SET explanation = 'Beef processing is a modern industrial practice that uses machines and factories, not a traditional scientific method passed down through generations in Botswana. Traditional scientific practices like fermentation (making madila or bojalwa), preservation (drying meat for biltong), and dyeing (making natural colors from plants) have been used by our ancestors for hundreds of years using their knowledge of nature and science. These traditional methods show how our people understood science long before modern laboratories existed!' WHERE id = 'efee136b-546d-4c42-855f-8db047c1ba08';
UPDATE questions SET explanation = 'Burning fuels like petrol, coal, and wood releases smoke and harmful gases into the air, which directly causes air pollution. While cutting down trees is harmful to the environment because trees help clean the air by absorbing carbon dioxide, the act of cutting them down doesn''t actually release pollutants into the air itself. Burning is the activity that puts dangerous particles and gases directly into the air we breathe.' WHERE id = '60e7ff8e-400a-4d5b-bdbb-3acf76f24948';
UPDATE questions SET explanation = 'Transpiration is the special process where plants release water vapour through tiny holes in their leaves called stomata, which is different from regular evaporation happening from soil or water surfaces. While evaporation might seem correct because both involve water turning into vapour, transpiration specifically refers to water loss from living plants as part of the water cycle. Think of it this way: when you see label 12 pointing to a plant, you know water is escaping through the leaves, not just evaporating from any surface.' WHERE id = 'f86bb775-e266-4555-a156-042b27630920';
UPDATE questions SET explanation = 'Tourism at Chobe National Park creates many jobs for local people who work in hotels, lodges, and campsites as cooks, cleaners, tour guides, and managers. These are positive ways that people earn money to support their families while helping visitors enjoy our beautiful wildlife. The other options describe negative activities that are illegal and do not show how tourism actually benefits communities living near the park.' WHERE id = '6e9a2900-b541-4d19-a9b6-7d4082445a9a';
UPDATE questions SET explanation = 'Weather describes what the atmosphere is like right now or over a few days at a specific place - like whether it''s hot, cold, rainy, or windy today in Gaborone. Option C might seem correct, but it actually describes climate, which is the pattern of weather over many years (like how Botswana is generally dry and hot). Weather changes quickly from day to day, while climate tells us what to expect over a long time.' WHERE id = '442db40d-3195-48e9-9bbd-8edad2ae2aa5';
UPDATE questions SET explanation = 'A goat eats grass and other plants, which makes it a primary consumer because it gets its energy directly from producers (plants). Grass is actually a producer because it makes its own food through photosynthesis, not a tertiary consumer. Dogs are also consumers that eat other organisms, not producers, and buffalos are primary consumers like goats since they only eat plants, not secondary consumers that would eat other animals.' WHERE id = 'ab25b913-fc06-4737-9a59-f1c5b7c8a80e';
UPDATE questions SET explanation = 'When Mothusi stirs sand in hot water, the sand particles are too large to break apart and mix with water, so they will sink to the bottom - we say sand does not dissolve. However, when he stirs salt in hot water, the salt breaks down into tiny particles that spread throughout the water and disappear, which means the salt dissolves completely.' WHERE id = '9e81b0de-77c7-469a-89b9-7b788ec7e637';
UPDATE questions SET explanation = 'A front is the boundary line where two different air masses meet, like when warm tropical air from the north meets cooler air from the south over Botswana. While option B might seem correct because cold air replacing warm air is one type of front (called a cold front), this is just one example, not the complete definition—fronts can also be where warm air replaces cold air or where air masses meet without replacing each other. Think of a front as the "border" between different types of air, just like the borders between countries.' WHERE id = '05ac05da-c9c7-480f-89a0-043df785e21d';
UPDATE questions SET explanation = 'Pepper is very light and can easily stick to objects with static electricity, while sand is too heavy to be attracted by a static charge, so you can use a charged object like a plastic ruler rubbed on cloth to pick up the pepper and leave the sand behind. Dissolving and filtering won''t work because neither pepper nor sand dissolve in water, and a magnet won''t help since neither material is magnetic. This method works great because pepper and sand have different weights and pepper responds to electrical charges!' WHERE id = '4da52286-dcc7-4b9b-87ab-beff04019cc8';
UPDATE questions SET explanation = 'Looking directly at the sun during a solar eclipse can seriously damage your eyes, so you need very strong protection that blocks harmful rays. Welding glasses are specially made with dark filters strong enough to protect your eyes from the sun''s dangerous light, while regular sunglasses are far too weak and won''t keep your eyes safe. Never use telescopes or binoculars to look at the sun because they actually make the sun''s rays stronger and can cause instant, permanent blindness.' WHERE id = '4e89a901-4022-4136-8875-7f444300eb13';
UPDATE questions SET explanation = 'Table salt is a compound because it is made when two different elements, sodium and chlorine, join together chemically to form something new with different properties. Carbon, oxygen, and potassium are all elements because they are made of only one type of atom and cannot be broken down into simpler substances by chemical means. Remember, compounds always contain two or more different elements bonded together!' WHERE id = '21708a0b-bac9-45e1-b599-774cf90f1c7a';
UPDATE questions SET explanation = 'Science careers welcome everyone regardless of gender because both men and women have the same ability to learn, discover, and solve problems through science. Throughout history and today in Botswana, we see successful scientists of all genders making important discoveries in medicine, technology, agriculture, and environmental protection. Your interest and hard work in science matter much more than whether you are male or female.' WHERE id = '4a5a0935-4103-4742-ab45-550da1c8cc98';
UPDATE questions SET explanation = 'Producers are organisms that make their own food using sunlight through photosynthesis, and sorghum is a plant that does exactly this. Animals like snakes, lions, and eagles are consumers because they must eat other organisms to get energy - they cannot make their own food from sunlight. Plants are the only true producers in nature because they can turn sunlight, water, and air into food for themselves and other living things.' WHERE id = 'd4ac7604-dd62-4141-97ba-7231027266c2';
UPDATE questions SET explanation = 'Antibiotics are special medicines that doctors give you when you have an infection caused by bacteria - they kill the harmful bacteria in your body without hurting your own cells. Option A might sound correct because antibiotics do help protect you from disease, but that describes vaccines, which prevent you from getting sick in the first place, while antibiotics treat bacterial infections you already have. Option B describes pasteurisation, which is a process used to make milk safe to drink by killing germs with heat.' WHERE id = '4da35e02-ad7d-42a2-99b5-80927e7a029f';
UPDATE questions SET explanation = 'When you keep adding sugar to water until no more sugar can dissolve and some remains at the bottom, you have made a saturated solution – the water is holding as much sugar as it possibly can at that temperature. An unsaturated solution would still be able to dissolve more sugar if you added it, but Marang''s solution cannot do this anymore because it has reached its maximum capacity.' WHERE id = '1f2a4487-4e34-4acb-b604-129ddec34894';
UPDATE questions SET explanation = 'A habitat is the natural home or place where specific plants and animals live, just like how you live in your house in your village or town. While an ecosystem might sound similar, it refers to all the living things in an area plus the non-living things like water and soil working together, which is much bigger than just a home. Think of a habitat as the address where an animal lives, like a bird''s nest in a tree or a fish''s home in a river.' WHERE id = '799eee62-28ea-4bef-ad48-8a18149b419b';
UPDATE questions SET explanation = 'National Parks and Game Reserves are modern ways of protecting wild animals because they create safe, protected areas where animals can live without being hunted or disturbed, and trained rangers can monitor and care for them. While beliefs, taboos, and totems are traditional methods that our ancestors used to protect certain animals, today we rely on official protected areas like Chobe National Park and the Okavango Delta where laws keep wildlife safe. These parks also allow us to enjoy watching our beautiful wildlife while ensuring they survive for future generations!' WHERE id = '85ef0b16-34f2-4e6d-8eaa-e109a5a4d18e';
UPDATE questions SET explanation = 'Bridges are structures built to help people and vehicles cross over rivers, valleys, or roads, so they are not designed to collect or store rainwater. Reservoirs, tanks, and dams are all specially designed to catch and hold water, including rainwater, so we can use it later for drinking, farming, and other important needs. Remember, in Botswana where water is precious, we use these storage methods to make sure we have enough water during dry seasons.' WHERE id = '03e69361-3d13-4819-be54-b1ebb83afbf2';
UPDATE questions SET explanation = 'When the Moon passes directly between the Sun and Earth, blocking the Sun''s light from reaching Earth, we call this a solar eclipse. The diagram shows this arrangement with the Moon casting a shadow on Earth. A lunar eclipse happens the other way around—when Earth blocks sunlight from reaching the Moon—so the positions would be different.' WHERE id = '5748043d-99fd-43cc-8ef0-b118a03c7dfd';
UPDATE questions SET explanation = 'When farmers and gardeners want to grow the best plants or breed the best animals, they carefully choose the healthiest and strongest ones to reproduce – this process is called selection. Distillation might sound scientific, but it''s actually about separating liquids by heating them, like making traditional bojalwa or purifying water. Selection helps us get better crops, stronger cattle, and healthier plants over time by choosing only the best ones for breeding.' WHERE id = '8a14413e-c035-45c6-b825-f8f805ca6f49';
UPDATE questions SET explanation = 'Learning about wildlife by watching nature around you is a cultural benefit because it helps pass down traditional knowledge and connects you to your community''s way of life, just like learning stories from elders. While this learning does help the environment, the question asks about the benefit to the children themselves – they are gaining cultural knowledge and understanding of their heritage. This type of learning strengthens your identity and helps you appreciate the wisdom that has been passed down through generations in Botswana.' WHERE id = '3aaccec0-dfb8-4e0d-b712-2a857d8765d1';
UPDATE questions SET explanation = 'Edward Jenner discovered vaccinations in 1796 when he used material from cowpox sores to protect a boy from the deadly smallpox disease, creating the world''s first vaccine. While Louis Pasteur later developed other important vaccines like the rabies vaccine, Jenner was the pioneer who started vaccination as we know it today. Alexander Fleming discovered penicillin (an antibiotic), which is different from vaccines because it treats infections rather than prevents them.' WHERE id = 'fc8353e6-d2a0-4b2f-b708-a4c126cef853';
UPDATE questions SET explanation = 'Rhinoceroses receive the most protection in Botswana because they are critically endangered and very few are left in the wild, making them targets for illegal poaching. Our government and wildlife organizations work hard to guard rhinos with armed anti-poaching units and special security measures. While animals like kudu and zebra are protected in our game reserves, they have much larger populations and don''t face the same risk of extinction as rhinos do.' WHERE id = 'a6f63ce9-2fa7-45c9-8b47-9e3779ee5931';
UPDATE questions SET explanation = 'Soft water is wonderful for washing because it lathers well with soap, creating lots of bubbles easily, which means you need less soap to get things clean. Hard water is the opposite – it''s the one that uses a lot of soap, doesn''t lather well, and leaves that white chalky fur on kettles and pots because it contains minerals like calcium. When you have soft water in your home, bathing and washing dishes becomes much easier and more economical!' WHERE id = '18fd3888-a139-4c2f-b764-37c11569286f';
UPDATE questions SET explanation = 'A suspension is when tiny solid particles float around in a liquid without dissolving, which makes the liquid appear cloudy or milky, like when you mix sand in water or shake up muddy water. The particles in a suspension don''t dissolve like sugar does in tea - instead they stay as separate pieces that can settle to the bottom if you leave the mixture standing for a while. This is different from dissolving, where the solid completely disappears into the liquid and won''t settle out.' WHERE id = '749154b3-cf78-49ae-bc75-d30cc405f9f7';
UPDATE questions SET explanation = 'Hard water contains minerals like calcium and magnesium that react with soap to form a scum instead of lather, which means you need to use much more soap to get things clean - this wastes soap! This is actually the opposite of saving money or using less soap, because you have to buy more soap when you have hard water. The minerals in hard water don''t affect how quickly it boils.' WHERE id = 'acf6454f-7f71-4b35-b0fe-0e7bbca6c8c0';
UPDATE questions SET explanation = 'Fish need water to survive, and a dam is a place where water collects, making it a perfect habitat where fish can live, swim, and find food. Hills, mountains, and trees are on land and don''t have the water that fish need to breathe through their gills and move around.' WHERE id = 'a545f9a8-2203-458c-84c3-dbb94e37f271';
UPDATE questions SET explanation = 'During a drought, there is not enough water for plants to grow well, and animals struggle to find water and food to survive. When living things cannot get what they need, many will die or move away to find better conditions, which causes the population to decrease. The population cannot increase or stay the same because drought makes it harder, not easier, for plants and animals to live and reproduce in that area.' WHERE id = 'd65b302d-c12f-4c07-8801-20b5d5642679';
UPDATE questions SET explanation = 'Alexander Forbes is not a famous scientist, while the other three people made groundbreaking discoveries that changed the world. Alexander Graham Bell invented the telephone, Thomas Edison created the light bulb, and Alexander Fleming discovered penicillin, which saves millions of lives by fighting infections. These three are celebrated as great scientists because their inventions and discoveries help people every day.' WHERE id = 'a6dea7a0-f67b-4734-8a49-a20fd04227b6';
UPDATE questions SET explanation = 'The Baobab tree is specially protected by law throughout Botswana because it is a national heritage tree that takes hundreds of years to grow and provides food, shelter, and medicine for people and animals. While Mophane trees are also very important and common in Botswana, they are not protected by law in the same way as the Baobab. Sorghum is a farm crop that farmers plant each year, so it doesn''t need special protection like our ancient Baobab trees do.' WHERE id = '4a4bfad5-6c2d-47e1-8f36-21de1a4eeefb';
UPDATE questions SET explanation = 'A dentist uses science to understand how teeth and gums work, and applies technology like X-ray machines, drills, and special materials to treat patients'' dental problems. While journalists and interpreters are important careers, they rely mainly on communication skills rather than scientific knowledge and medical equipment. Dentists must study biology, chemistry, and use advanced tools to keep our teeth healthy!' WHERE id = '32867ae9-a144-4f62-a67b-eb949e546dc3';
UPDATE questions SET explanation = 'When a scientist uses information and evidence to say what will happen in the future, they are making a prediction - just like predicting if it will rain tomorrow based on dark clouds in the sky. While scientists do communicate their ideas to others, communicating means sharing information, not specifically telling what will happen next. Predicting is the special word we use when someone makes an informed guess about future events based on what they know.' WHERE id = '68f6d82e-580e-4797-8bbc-f0450816f4ab';
UPDATE questions SET explanation = 'When water boils in a pot, you can see bubbles forming throughout all the water, even at the bottom, because boiling happens everywhere inside the liquid at once. Evaporation is different - it only happens at the top surface of the water, which is why puddles can slowly dry up even on cool days without boiling. Remember that both boiling and evaporation change liquid water into water vapor (gas), but they happen in different parts of the liquid.' WHERE id = '94cc2008-5a97-4608-b16b-72f3be083db2';
UPDATE questions SET explanation = 'Air is a mixture of different gases, and oxygen makes up about 21% of it - this is the gas we breathe in to stay alive! You might have thought it was nitrogen because that gas actually makes up most of the air (about 78%), but nitrogen is much more common than oxygen in our atmosphere.' WHERE id = '86dd6ae5-f5c5-4b2f-9556-42c61d25fb0e';
UPDATE questions SET explanation = 'When you add salt to ice, the salt breaks apart the ice structure and makes it harder for water molecules to freeze together, so the ice melts at a lower temperature than normal (below 0°C). This is why we sometimes put salt on icy roads in cold countries - it helps the ice melt even when the air temperature is still freezing! The melting point doesn''t stay the same because the salt actually changes what''s happening between the water molecules.' WHERE id = 'c5bf5af8-e8d7-49c4-abd0-a30449dbb872';
UPDATE questions SET explanation = 'The four inner planets closest to the Sun are Mercury, Venus, Earth, and Mars, which are all rocky planets that form the inner solar system. Saturn, Jupiter, and Uranus are much larger gas giant planets that orbit farther away from the Sun in the outer solar system. Mars is correctly called an inner planet because it sits between Earth and the asteroid belt that separates the inner planets from the outer ones.' WHERE id = 'b654ad9b-2dfa-48ee-a8ec-3af1759e34e4';
UPDATE questions SET explanation = 'Animals are divided into two main groups based on whether they have a backbone or not. Invertebrates are animals without a backbone, like insects, spiders, and worms, while vertebrates are animals with a backbone, like humans, fish, and birds. Carnivores and herbivores describe what animals eat (meat or plants), not whether they have backbones, so these are incorrect choices.' WHERE id = 'f7247a42-bca3-4f14-9da7-c712c439c5f0';
UPDATE questions SET explanation = 'Washing soda is a special chemical that removes the minerals (like calcium and magnesium) that make water hard, turning it into soft water that creates a better lather with soap. Using less soap doesn''t actually change the hardness of the water - it just means you''re using less soap with hard water, which will still give you poor washing results. Adding salt would actually make the water worse for washing, not better!' WHERE id = 'c0015b0c-5d22-4615-a868-73d8baaed070';
UPDATE questions SET explanation = 'Looking at the diagram, you can see the moon appears as a complete, bright circle, which means we are seeing the entire sunlit side of the moon from Earth - this is called a full moon. The quarters (first and second) would only show half of the moon''s face lit up, while a new moon would appear completely dark because the sunlit side faces away from us.' WHERE id = '16189717-3bde-4425-b608-2a58b0db4963';
UPDATE questions SET explanation = 'Science careers are for everyone, regardless of whether you are male or female, and you can start preparing for them while you are still young by studying hard in school. Both men and women work as doctors, engineers, botanists, and researchers all over Botswana and the world, and they all began learning science when they were students just like you. Age doesn''t matter either – you start building your science career through your education now, not when you are old.' WHERE id = '7c689d12-7906-40fc-a778-0dc59d235582';
UPDATE questions SET explanation = 'Thomas Fleming is not a famous scientist because he is not a real person who made important discoveries. The other three are all real scientists: Alexander Graham Bell invented the telephone, Alexander Fleming discovered penicillin (an important medicine), and Alexander Forbes studied the nervous system. You might have been confused because Alexander Fleming sounds similar to Thomas Fleming, but only Alexander Fleming is the actual scientist.' WHERE id = '8e0dd3bf-9f0d-49f2-8c06-151821977eb2';
UPDATE questions SET explanation = 'Grass is correctly classified as a producer because it makes its own food using sunlight through photosynthesis, just like all green plants do. A cow cannot be a producer because it eats grass to get energy rather than making its own food, which makes it a consumer (specifically a herbivore). Remember, only organisms that can make their own food from sunlight, like plants, are producers in the food chain.' WHERE id = 'abcdc7b5-7c0d-4f63-809e-47dd7d2aa2ee';
UPDATE questions SET explanation = 'Hunting big predators like lions, leopards, and cheetahs actually reduces animal populations and harms the ecosystem, so it is not a way of conserving animals. Traditional conservation methods like totems, beliefs and taboos protected certain animals by making it forbidden to kill them, which helped keep those animal populations safe for future generations. Hunting all year round might sound wrong, but some communities traditionally hunted throughout the year in controlled, sustainable ways that didn''t threaten animal populations.' WHERE id = 'c145d1d3-1373-4ee2-be6b-0427d82cef9c';
UPDATE questions SET explanation = 'The Mophane tree is legally protected throughout Botswana because it is so valuable to our country - it provides food for mopane worms, which many people depend on for income and nutrition, and its wood is used carefully for many purposes. While the Baobab is also an important and protected tree in Botswana, it is the Mophane that has special protection laws covering the entire country. Both trees are precious to our environment, but Mophane''s protection is nationwide due to its economic and ecological importance.' WHERE id = 'f8234df9-a166-42bb-8342-531228409f55';
UPDATE questions SET explanation = 'National parks and game reserves are the modern way we protect wild animals in Botswana because they provide safe, protected areas where animals can live without being hunted or disturbed, and trained rangers can monitor and care for them. While beliefs, taboos, and totems were traditional ways our ancestors protected animals and are still important culturally, today we rely on official protected areas like Chobe National Park and the Central Kalahari Game Reserve to keep our wildlife safe for future generations.' WHERE id = 'a8d39602-7e5c-4c7c-b498-c04297be8083';
UPDATE questions SET explanation = 'Wild dogs are mostly protected in Botswana because they are endangered animals with very small populations left in Africa, and our country has one of the largest remaining groups of them in the world. While zebras and kudus are also wild animals found in Botswana, they have much larger populations and are not as threatened with extinction, so they don''t need the same level of special protection. Cows are domestic farm animals that people raise for food and milk, so they don''t need wildlife protection.' WHERE id = 'fbf6ddcd-54cf-4f3d-a9d6-5216b854076b';
UPDATE questions SET explanation = 'When tourists visit protected areas like game reserves, they buy handmade crafts, baskets, and other curios from local communities, which helps these families earn money to support themselves. This is one of the main ways conservation helps people living near wildlife areas. While communities might sometimes guide tourists as part of their work, simply walking with tourists doesn''t provide the regular income that selling goods does.' WHERE id = '128792fe-cb48-4928-82b9-9e9a2aa9497f';
UPDATE questions SET explanation = 'When water has dissolved as much solute as it possibly can and no more solute will dissolve, we call this a saturated solution - think of it like a sponge that is completely full of water and cannot absorb any more. An unsaturated solution, on the other hand, still has room to dissolve more solute, just like a dry sponge can still absorb more water. The word "saturated" means completely full or soaked, which perfectly describes this situation.' WHERE id = '6cb4b030-f74e-474a-b290-9c2685217976';
UPDATE questions SET explanation = 'A suspension is when solid particles float or hang in a liquid without dissolving, like when you shake sand in water and the sand particles spread throughout but don''t disappear. While option D sounds similar because it mentions particles not dissolving, the key feature of a suspension is that the particles actually float around in the liquid rather than just sitting at the bottom. Think of muddy water from the Limpopo River – the dirt particles stay mixed in the water for a while before settling down.' WHERE id = '350a1aad-48a3-4a94-8ceb-c0ad3897937a';
UPDATE questions SET explanation = 'Climate is the pattern of weather that a place experiences over many years, usually 30 years or more, which is why we say Botswana has a semi-arid climate with hot summers and mild winters. Option B might seem correct, but it actually describes weather, not climate – weather is what happens day-to-day or week-to-week, like today''s temperature or yesterday''s rain. Think of it this way: weather is what you wear today, but climate is the types of clothes you keep in your wardrobe all year round.' WHERE id = 'd5342aff-b136-48ec-b4d6-74d2ddd286a7';
UPDATE questions SET explanation = 'Looking directly at the sun during a solar eclipse can permanently damage your eyes, so you need special eclipse goggles that are designed to block harmful solar rays while letting you view the eclipse safely. Regular sunglasses, binoculars, and telescopes are not safe because they don''t block enough of the sun''s dangerous light, and binoculars or telescopes actually make it worse by concentrating the sun''s rays and burning your eyes even faster.' WHERE id = '7648a2a2-1f12-41eb-a7d8-ecaae1ccbcd7';
UPDATE questions SET explanation = 'Weather describes what the atmosphere is like right now or over just a few days – like whether it''s hot, rainy, or windy today in Gaborone. When we talk about conditions over a long period of time, like many years, that''s called climate, not weather. Think of it this way: weather is what you wear today, while climate helps you decide what clothes to keep in your wardrobe all year round.' WHERE id = '3b259e35-0d70-4094-9526-9940dcdbb3a7';
UPDATE questions SET explanation = 'A new moon happens when the moon is between the Earth and the Sun, so the side of the moon facing us gets no sunlight and appears completely dark in our sky. This is different from when half the moon is in shadow, which we call a quarter moon or half moon. The new moon occurs once every month, not three times, as part of the moon''s regular cycle around Earth.' WHERE id = 'b7e40dda-b6fb-464c-969b-5a52d5a5c186';
UPDATE questions SET explanation = 'A warm front forms when a mass of warm air moves forward and pushes up over colder air that was already in an area, replacing it. You might have been tempted by option A, but that describes a cold front instead, which is the opposite situation where cold air pushes under and replaces warm air. Think of it this way: the word "warm front" tells you that warm air is at the front, leading the movement!' WHERE id = 'b5f2e926-6089-40ea-a609-73cc9e277673';
UPDATE questions SET explanation = 'An anti-cyclone forms when cold, heavy air sinks down towards the Earth''s surface, creating an area of high air pressure—just like when you push down on water, the pressure increases at the bottom. Options A and D describe weather fronts, which are different weather features where two different air masses meet and move past each other, not areas of sinking air. Anti-cyclones bring us clear, calm weather because the sinking air stops clouds from forming.' WHERE id = 'd1befd64-c3f6-4b25-ab48-e5e5149f0fd1';
UPDATE questions SET explanation = 'A cold front happens when a mass of cold air moves in and pushes the warm air out of the way, replacing it at ground level. This is different from option D because the cold air is doing the replacing, not being replaced - imagine cold air sliding under warm air like a wedge and forcing it upward. While cold air does create high pressure (option B), a cold front specifically describes the boundary where this replacement is happening, not just the high pressure area itself.' WHERE id = 'ce465363-bef8-4355-bd52-bc5b3f688f40';
UPDATE questions SET explanation = 'Iron is a pure element made of only one type of atom, which means it cannot be a compound. Compounds like water are made when two or more different elements join together chemically, such as hydrogen and oxygen combining to form water. Remember that elements are the building blocks, while compounds are what you get when different elements bond together!' WHERE id = 'ae1d904a-6b15-4cb2-b987-c3dab171484e';
UPDATE questions SET explanation = 'A habitat is the natural home where an organism lives, just like your house is your home. It includes the specific place where a plant or animal naturally lives and finds everything it needs to survive, such as a bird living in a tree or a fish living in a river. While option D might seem close, a habitat is more than just surroundings – it''s the actual home itself where the organism belongs.' WHERE id = '9129ba9f-6388-4d72-937c-6050b743e8ac';
UPDATE questions SET explanation = 'A dam is a large structure built across a river or valley that collects and stores huge amounts of rainwater for entire communities, farms, and towns to use. While tanks can also store rainwater, they are much smaller and only hold enough water for one household or building. Dams like the ones you might have seen around Botswana can hold millions of litres of water, making them perfect for collecting rainwater in large quantities.' WHERE id = 'b8ce5dc1-a192-44b1-bed0-74b9f4924c2b';
UPDATE questions SET explanation = 'When a substance changes from liquid to solid, it loses heat energy and becomes harder, which is exactly what happens during freezing – think of water turning into ice in your freezer. Melting is the opposite process where a solid turns into a liquid when it gains heat, like ice cream melting in the sun. The arrow Z shows the direction from liquid to solid, so it must represent freezing.' WHERE id = '23e51626-f886-42ec-a581-9ff5296417be';
UPDATE questions SET explanation = 'Iron is represented by the symbol Fe, which comes from its Latin name "ferrum." This is why we see Fe on the Periodic Table instead of just I, which helps avoid confusion with other elements. Lead might seem tempting because it''s also a well-known metal, but lead''s symbol is actually Pb (from the Latin word "plumbum").' WHERE id = 'a3b0d253-29dd-4b31-b961-288ea9240199';
UPDATE questions SET explanation = 'An element is made up of only one type of atom, so when you have the same atoms joined together, you form an element like oxygen or gold. Different atoms joining together would actually form a compound, not an element, because compounds are made when two or more different types of atoms combine.' WHERE id = '4b635183-43f7-4f78-af31-83d46a9116e5';
UPDATE questions SET explanation = 'Wind direction on weather charts is shown using an arrow symbol that points in the direction the wind is blowing toward, which is what Option C shows. This arrow makes it easy to see at a glance which way the wind is moving across different areas on the map. Some students might confuse this with other weather symbols like those for rain or temperature, but the arrow is specifically designed to show movement and direction of wind.' WHERE id = 'f227100a-a293-4c0c-a510-5a582e830929';
UPDATE questions SET explanation = 'To separate pepper and sand, you would first add water to dissolve any soluble materials, then filter the mixture to separate the solid particles, and finally use a magnet to attract and remove any magnetic materials like iron particles that might be in the sand. A permanent magnet alone (option D) wouldn''t work because neither pepper nor sand are magnetic materials, so the magnet would not attract them. This method combines three different separation techniques to ensure you can separate all the components effectively.' WHERE id = '7e1663f0-f157-4e46-acc2-f072e98f6666';
UPDATE questions SET explanation = 'The water cycle follows a natural order where water from rivers, lakes, and oceans heats up and rises into the sky as water vapor (evaporation), then cools down to form clouds (condensation), and finally falls back to Earth as rain or snow (precipitation). Option A is incorrect because rain must fall from clouds that have already formed, so precipitation cannot happen before evaporation and condensation. This cycle keeps repeating, providing us with the water we need for drinking, farming, and all life in Botswana.' WHERE id = 'b9df700b-08f1-4288-8ec2-a0abdd6bf6fc';
UPDATE questions SET explanation = 'Vaccination is a way to protect your body against diseases before you even get sick by helping your immune system learn to fight off germs. It''s different from taking medicine to cure a disease you already have, which is what option C might make you think. Vaccines prevent diseases like measles, polio, and tetanus by training your body to recognize and fight them if you''re ever exposed.' WHERE id = '22d2abb0-4cf8-441d-adad-466f7eb2acb5';
UPDATE questions SET explanation = 'When you add salt to ice, the melting point decreases, which means the ice will melt at a temperature lower than 0°C. This is why we sometimes put salt on icy roads in cold places – the salt helps the ice melt even when the temperature is below freezing. The salt particles get between the water molecules and make it harder for them to form solid ice, so the ice needs to be colder to stay frozen.' WHERE id = 'bae323f0-d50f-481d-a519-1af73584caae';
UPDATE questions SET explanation = 'Making clay pots is a traditional scientific practice in Botswana because it involves observing nature, understanding which clay works best, and applying knowledge of heat and materials that has been passed down through generations. While beef processing is an important industry in Botswana today, it uses modern technology rather than traditional methods. Car and computer manufacturing are modern industrial practices that are not traditionally done in Botswana.' WHERE id = '1cdae68b-1f68-4434-9c7a-8ae7c45d01e2';
UPDATE questions SET explanation = 'Alexander Fleming is the scientist who discovered penicillin in 1928 when he noticed that mold killed bacteria in his laboratory. Louis Pasteur was also an important scientist who studied diseases and germs, but he lived earlier and worked on vaccines, not antibiotics like penicillin. This discovery by Fleming was very important because penicillin became the first antibiotic medicine that saved millions of lives from bacterial infections.' WHERE id = 'bfa0a1ec-7211-4c86-964b-fc6e1fdf4143';
UPDATE questions SET explanation = 'Pasteurization is a special process where we heat milk to just the right temperature (not as hot as boiling) and then cool it down quickly to kill harmful germs that could make us sick. This is different from boiling milk at a high temperature, which would make the milk taste different and destroy some of the good nutrients we need. The careful heating and quick cooling keeps milk safe to drink while maintaining its fresh taste and nutritional value.' WHERE id = 'a041113a-257c-454f-8eeb-d997515525ec';
UPDATE questions SET explanation = 'A population is the total number of organisms of the same species living together in one area, like all the zebras in the Okavango Delta or all the acacia trees in a certain part of the savanna. You might have thought it was a community, but a community includes many different types of organisms living together, not just one type. Remember: population = one species, community = many different species together!' WHERE id = '22692ee7-756c-4eed-aaad-dd293277a7dd';
UPDATE questions SET explanation = 'When children learn about wildlife by watching animals in their surroundings, they develop knowledge and appreciation that becomes part of their community''s way of life and traditions - this is a cultural benefit because it shapes how people understand and value nature as part of their heritage. While this might seem social since it involves people learning together, cultural benefits specifically relate to knowledge, beliefs, and practices that are passed down through generations. This traditional knowledge helps communities protect wildlife because they understand its importance to their identity and history.' WHERE id = '72cacef7-5b36-4bcb-922b-677a83cdcc13';
UPDATE questions SET explanation = 'When we burn fuels like petrol, diesel, coal, or wood, smoke and harmful gases are released into the air, which directly causes air pollution. While cutting down trees (option A) is harmful to the environment because trees help clean the air, it doesn''t directly release pollutants into the air the way burning fuels does. Burning is the activity that actually puts dirty smoke and gases into the air we breathe.' WHERE id = '7dfbb353-eab6-4f6a-a4c6-25e2c3cd7136';
UPDATE questions SET explanation = 'When factories dump unwanted chemicals directly into rivers, those harmful substances mix with and contaminate the water, causing water pollution. This makes the river water unsafe for drinking, bathing, and can harm fish and other water animals. Even though factories might also cause air pollution through their smoke and chimneys, the question specifically tells us the chemicals are being disposed into rivers, which means the pollution happens in the water itself.' WHERE id = 'aac71136-c428-49ef-90bb-b6572b7cf49d';
UPDATE questions SET explanation = 'When too many people live in one area, they create more pollution from cars, factories, and burning fuel, which makes the air dirty and harmful to breathe. This polluted air damages our lungs and causes respiratory diseases like asthma and bronchitis, making it harder for people to breathe properly. Overpopulation actually makes people less healthy, not stronger, because crowded conditions also spread diseases more easily and put pressure on hospitals and clean water supplies.' WHERE id = 'f6954fe5-1e71-4646-ac22-6322f06096b3';
UPDATE questions SET explanation = 'When a substance dissolves and disappears in water like the salt did, we call that substance soluble in water. Sand did not dissolve, so we say sand is insoluble in water. While it''s true that salt becomes a solute when it dissolves in water, the word "soluble" is the correct term to describe salt''s ability to dissolve.' WHERE id = '465ead0b-a87c-4bfb-8334-2288273dbadf';
UPDATE questions SET explanation = 'Hard water contains minerals like calcium and magnesium that make it difficult to form soap lather, so it definitely does not lather well with soap. This means option C is not true about hard water because it says the opposite - that hard water lathers well, which is incorrect. Hard water actually wastes soap because you need to use more of it to get bubbles, and it leaves white chalky deposits (fur) on kettles and pots.' WHERE id = 'b0a70c19-fad3-470c-8342-71303f6f34d5';
UPDATE questions SET explanation = 'Hard water contains dissolved minerals like calcium and magnesium, and when you heat this water in a kettle, these minerals settle and form a white, chalky layer called fur or scale on the inside. This fur buildup is a real problem because it makes the kettle less efficient and harder to clean. Option D might seem correct because hard water does actually use more soap (not less) since the minerals react with soap and make it harder to form lather.' WHERE id = 'f439a3a5-de59-4cfd-a1e3-905ef789185f';
UPDATE questions SET explanation = 'When a substance dissolves, stirring helps mix it faster, heating gives particles more energy to break apart, and smaller particle size means more surface area touches the liquid. Humidity, which is the amount of water vapor in the air around you, does not affect how fast something dissolves in a liquid because dissolving happens inside the solution, not in the air outside it.' WHERE id = 'c56bc8b8-824e-430b-9d47-17e9588765f1';
UPDATE questions SET explanation = 'During a lunar eclipse, the Earth passes directly between the Sun and the Moon, causing the Moon to move into Earth''s shadow and appear dark or reddish in our sky. Option C might sound correct, but that''s actually describing a solar eclipse, where the Moon passes between Earth and the Sun, blocking sunlight from reaching parts of Earth. Remember: lunar eclipse means the Moon gets dark, solar eclipse means the Sun gets blocked from our view!' WHERE id = '5aa7d612-62f9-4205-9b92-8de23b91cd02';
UPDATE questions SET explanation = 'Air pollution happens when harmful substances are released into the air we breathe, and poisonous gases from factories, vehicles, and burning materials directly pollute our atmosphere. While throwing waste in water causes water pollution and littering on land causes land pollution, these don''t affect the air quality. Remember, each type of pollution affects a different part of our environment - air, water, or land!' WHERE id = 'dff3ca2d-30b3-48b8-aa4d-802389ec5b1d';
UPDATE questions SET explanation = 'Mechanical engineering is a career where people design and build machines like cars, engines, and factory equipment by using scientific principles such as forces, energy, and materials, along with technology like computers and tools. While journalism might seem like it uses technology because reporters use phones and cameras, the main work is about gathering and writing news stories, not applying scientific knowledge to solve technical problems. Scientists and engineers use their understanding of how things work in nature to create new inventions and improve existing machines.' WHERE id = 'ea6fc521-4d95-4df9-9c77-51f9d97a1f72';
UPDATE questions SET explanation = 'When people drink polluted water, harmful germs and chemicals enter their bodies, which makes them become sick with diseases like diarrhea, cholera, or typhoid. Clean water keeps us healthy, while polluted water does the opposite - it cannot make us well or wise, and it definitely does not contain alcohol to make people drunk. This is why it is so important to always drink clean, safe water from protected sources.' WHERE id = '7e7a4389-f57c-4245-a4e3-5892b1d64eed';
UPDATE questions SET explanation = 'When we talk about social benefits, we mean things that bring happiness, enjoyment, and better quality of life to people in our communities. Enjoying viewing wildlife like elephants at Chobe or giraffes in the Okavango Delta is a social benefit because it brings joy to families and visitors, making our lives richer and more meaningful. Employment and tree planting are important benefits of conservation too, but they are economic and environmental benefits rather than social ones.' WHERE id = 'dfb7f621-34d7-46ff-8969-339e91e50632';
UPDATE questions SET explanation = 'The invention of the wheel made vehicles much more comfortable because wheels allow smooth rolling movement instead of dragging or bumping along rough ground. Before wheels, people had to carry heavy loads on their backs or drag them, which was very uncomfortable and tiring. Wheels also helped vehicles travel faster and use less energy, not more fuel as option C suggests, making transportation easier and more pleasant for everyone.' WHERE id = '68331b10-72f5-4f3c-8dfd-c63caea734cc';
UPDATE questions SET explanation = 'Rain water lathers easily with soap because it is soft water, meaning it contains very few dissolved minerals like calcium and magnesium. Borehole water and well water often contain many dissolved minerals from underground rocks, making them hard water that doesn''t lather well with soap. Sea water is also very hard because it contains lots of dissolved salts, which is why it''s difficult to create soap lather in ocean water.' WHERE id = '0b6fd181-a838-4fd6-8859-7547727f70e5';
UPDATE questions SET explanation = 'Tourism creates many opportunities for people living near the Okavango Delta to earn money by selling crafts, offering guided tours, providing accommodation, and sharing their local knowledge with visitors. This business relationship helps families support themselves while protecting the delta''s wildlife and natural beauty. The other options describe harmful activities that would actually chase tourists away and are not the real benefits that local communities gain from tourism.' WHERE id = 'bdd96105-f31d-4278-a59f-83148bb77424';
UPDATE questions SET explanation = 'A secondary consumer is an animal that eats primary consumers (plant-eaters). The snake is a secondary consumer because it eats the chicken and grasshopper, which are primary consumers that feed on plants. The grasshopper and chicken are primary consumers themselves, while the vulture is a scavenger that feeds on dead animals, making it different from a typical secondary consumer.' WHERE id = 'f302dfea-a347-4cd0-a3fb-f51db16e6d2e';
UPDATE questions SET explanation = 'Grass is a producer because it makes its own food using sunlight, water, and air through a process called photosynthesis. Birds, worms, and eagles are all consumers because they cannot make their own food and must eat other living things to survive. Producers like grass are always plants because only plants can trap the sun''s energy to create food.' WHERE id = '99732447-ad09-4775-8b5e-de3efdb61456';
UPDATE questions SET explanation = 'During a drought, there is not enough water for plants to grow well, and many plants die. When plants die or become scarce, animals don''t have enough food and water to survive, so many animals also die or move away to find better conditions, which means the population decreases. The population cannot increase or stay the same because living things need water to survive, and more animals would not come to an area where resources are scarce.' WHERE id = '5543aa20-1238-412b-8aa4-e5317c132975';
UPDATE questions SET explanation = 'Fermentation is the special process where tiny living things called yeast break down sugars and change them into alcohol and carbon dioxide gas. This is how drinks like traditional beer are made! Distillation is different – it''s a process that happens after fermentation, where liquids are heated to separate alcohol from water to make it stronger.' WHERE id = '5a43f879-6176-4ca3-82c3-b093630b713b';
UPDATE questions SET explanation = 'A community in ecology includes all the living things in an area - both plants AND animals living together, like the acacia trees, grass, zebras, and lions all sharing the savanna. Option A is incorrect because a community must have different types of organisms, not just identical plants, and it must include animals too, not only plants. Think of your village community - it has many different people working together, just like an ecological community has many different species living together!' WHERE id = 'cda89e43-3528-4644-9aea-8b088330bec1';
UPDATE questions SET explanation = 'Alexander Graham Bell is famous for inventing the telephone in 1876, which allowed people to speak to each other across long distances for the first time. While Thomas Edison invented the electric light bulb, Bell''s telephone revolutionized communication and made it possible for families and businesses around the world to stay connected. His invention was so important that we still use telephones today, though they now look very different from his original design!' WHERE id = 'b79c3263-ceda-4748-a092-f7e7c708442c';
UPDATE questions SET explanation = 'A lunar eclipse happens when the Earth moves between the Sun and the Moon, blocking sunlight from reaching the Moon. This can only occur during a full moon because that''s when the Moon is on the opposite side of Earth from the Sun, allowing Earth''s shadow to fall on it. While every lunar eclipse needs a full moon, not every full moon creates an eclipse because the Moon''s orbit is slightly tilted, so Earth''s shadow usually misses the Moon.' WHERE id = '7db1c0b7-d6fc-49f5-9fe4-8e35a0e7975c';
UPDATE questions SET explanation = 'When the Moon is on the opposite side of Earth from the Sun, the entire side facing us is lit up brightly, which we call a full moon. A new moon happens when the Moon is between Earth and the Sun, so we cannot see it at all because the lit side faces away from us. By looking at where the Moon is positioned relative to Earth and the Sun in the diagram, you can tell which phase people in town X will observe.' WHERE id = '579af320-58d0-4017-ab4c-23cc5be7023f';
UPDATE questions SET explanation = 'When salt mixes with hot water, it breaks down into tiny particles that spread throughout the water and disappear - this is called dissolving. Cooking oil, however, does not dissolve in water because oil and water do not mix together; instead, the oil floats on top or forms separate droplets no matter how much you stir.' WHERE id = '28a615db-f6b5-4357-9629-e0b33377ddf8';
UPDATE questions SET explanation = 'When you need salt to dissolve quickly in your food that''s already prepared, fine salt works best because its tiny grains have more surface area and mix into your dinner almost immediately. Coarse salt has larger crystals that take much longer to dissolve, so you might end up with crunchy bits of salt in some bites while other parts of your food have no salt at all.' WHERE id = 'a668569c-566b-4bc7-bf89-48474cb27704';
UPDATE questions SET explanation = 'When hard water is heated in pipes or kettles, minerals like calcium and magnesium form a hard, crusty layer called fur (also known as limescale). While scum is also caused by hard water, it forms on top of water when soap is mixed with it, not on the pipes themselves. Carbonate and calcium are chemicals that make up fur, but fur is the name we give to the whole deposit that builds up.' WHERE id = 'b3fc7755-cd34-4c39-a7dd-2cb486d88ca4';
UPDATE questions SET explanation = 'Sugar dissolves faster in hot water because heat makes water molecules move more quickly, allowing them to break down and mix with the sugar particles more rapidly. Both boiling water (the hottest) and warm water will dissolve sugar much faster than cold water, which is why option D is correct. Option A is tempting, but warm water also dissolves sugar quickly, so we should include both types of hot water in our answer.' WHERE id = '2155b803-2a02-42b0-a81c-0958e5ac2ca8';
UPDATE questions SET explanation = 'Drying of mophane worms is a traditional scientific practice because it uses knowledge of the sun and heat to preserve food for later use, which involves understanding how moisture removal prevents spoilage. Making chibuku and processing flour are food preparation methods, but they are not considered scientific practices in the traditional sense. The drying process shows how our ancestors used scientific observation and methods to solve real problems in their daily lives.' WHERE id = '1c7b2616-2e55-444b-8276-2809163061ca';
UPDATE questions SET explanation = 'When a solution cannot dissolve any more solute (like sugar) because it has reached its maximum capacity, we call it a saturated solution. An unsaturated solution can still dissolve more sugar, which is the opposite of what happened in Neelo''s experiment. Think of it like a sponge that has soaked up all the water it possibly can – it''s completely full or "saturated."' WHERE id = 'b24cd5da-5976-4065-b21a-b3ed3a27b279';
UPDATE questions SET explanation = 'A habitat is the natural home or environment where an organism lives, just like how you live in your house or village. It includes everything the organism needs - food, water, shelter, and space - not just one thing like feeding or reproducing. While organisms do feed and reproduce in their habitats, these are just activities that happen there, not what defines a habitat itself.' WHERE id = 'f16a2359-95d7-4fb4-9909-c00097210650';
UPDATE questions SET explanation = 'Sodium is a soft, silvery metal element, and scientists use the chemical symbol Na to represent it, which comes from its Latin name "natrium." You might think the symbol should be "So" because it starts with those letters, but chemical symbols often come from Latin or Greek names, which is why sodium uses Na instead. Another element, potassium, uses the symbol K (from its Latin name "kalium"), so it''s important to learn these special symbols rather than just guessing from the English name.' WHERE id = '1512c6e6-aa1e-4b4c-8501-9036654bfee7';
UPDATE questions SET explanation = 'When people drink polluted water, they become sick because the water contains harmful germs, chemicals, or dirt that can cause diseases like diarrhea, cholera, or typhoid. Clean, safe water is what keeps our bodies healthy and strong, not polluted water which does the opposite by making us ill. This is why it''s so important to always drink clean water from safe sources like treated taps or protected wells.' WHERE id = 'b45f917a-7aa4-4cf2-bc7d-e7976361a62d';
UPDATE questions SET explanation = 'Science actually encourages people to be active, curious, and hardworking as they explore, experiment, and discover new things. The other options are all true benefits of science – it helps us solve everyday problems, improves our quality of life through better technology and resources, and has led to discovering medicines that save millions of lives. Being lazy is the opposite of what science promotes, as scientists must be dedicated and persistent in their work.' WHERE id = '3dec3b03-2d78-49da-990d-3ad55975582b';
UPDATE questions SET explanation = 'An ecosystem includes both the living things like plants, animals, and insects, AND the non-living things like water, soil, air, and sunlight that all work together in an area. Think of the Okavango Delta - it''s not just the elephants and fish living there, but also the water, sand, and sunshine that make it a complete ecosystem. Option A might seem correct, but it only mentions living organisms and forgets the important non-living parts like water and soil that living things need to survive.' WHERE id = '6da9ab6d-ac8a-4287-b61f-66ebe1e623b9';
UPDATE questions SET explanation = 'Grass is a producer because it makes its own food using sunlight, water, and air through photosynthesis. Animals like zebras, lions, and eagles are all consumers because they must eat other living things to get energy - they cannot make their own food like plants do. Producers are always plants or plant-like organisms that start the food chain by capturing energy from the sun.' WHERE id = '9dc92a46-c3f4-4c47-ae67-6b08a4d17843';
UPDATE questions SET explanation = 'A population is a group of the same type of organism living together in one place, like a group of impalas in the Okavango Delta or all the mopane trees in one area. Remember that a population must be the same species - if you count all the different animals together, that would be a community, not a population. This is why option A is incorrect, as it mixes different animal species together instead of focusing on just one type.' WHERE id = 'e37c9976-15e1-4a00-8a34-bb0a43e523ea';
UPDATE questions SET explanation = 'A food chain shows how energy flows from plants to animals, always starting with a producer like grass that makes its own food from sunlight, then moving through consumers from smallest to largest. Option B is correct because it follows this natural order: grass feeds insects, insects are eaten by frogs, frogs are eaten by snakes, and snakes are eaten by hawks. Option A is backwards - hawks cannot give energy to snakes, and animals cannot give energy back to grass!' WHERE id = 'a47963e8-4610-48c1-9c0d-bab3ee2664c8';
UPDATE questions SET explanation = 'An element is a pure substance made of only one type of atom, like zinc or oxygen, while a compound is made of two or more different elements chemically joined together, like water which contains hydrogen and oxygen atoms bonded together. Zinc is correctly identified as an element because it contains only zinc atoms, and water is a compound because it''s made from hydrogen and oxygen combined. Remember that oxygen and hydrogen by themselves are both elements, not compounds, so option B incorrectly labels hydrogen as a compound when it''s actually an element on its own.' WHERE id = '1b05c0cc-d528-4511-aae3-cd3149002b12';
UPDATE questions SET explanation = 'When a candle burns, the wax (which is a chemical) breaks down and releases energy that we can see as light from the flame and feel as heat warming the air around it. This is why the answer is chemical to light and heat energy. Option C might seem correct because we often see electrical devices producing light, but a candle doesn''t use electricity at all – it uses the stored chemical energy in the wax itself.' WHERE id = 'cb91daa7-de1a-41fb-9226-c6e1ec835cfe';
UPDATE questions SET explanation = 'When you stir salt and sugar into water, they both dissolve completely and form a clear solution, making them soluble substances. Flour and mealier-meal might seem to mix with water at first, but they actually just float around and settle at the bottom instead of dissolving - try this at home and you''ll see the water stays cloudy! Sand never dissolves in water either, so even though sugar does, sand and sugar together aren''t both soluble.' WHERE id = 'b5895a0f-c686-4376-9d09-09bd997b4b27';
UPDATE questions SET explanation = 'Heat from the sun travels through empty space and air without needing any material to carry it – this special way of heat traveling is called radiation, just like how sunlight warms your skin even though you''re not touching the sun. Convection is different because it needs air or liquid to move around in circles to carry the heat, like when hot air rises in a room. Radiation is the only way heat can travel through space where there is no air at all, which is why the sun''s warmth can reach Earth.' WHERE id = '06a45606-9452-4de7-8606-01353ef79ce9';
UPDATE questions SET explanation = 'When you look in a plane mirror, like the one in your bathroom, the image you see is always exactly the same size as you are. The mirror doesn''t make things smaller like when you step back from something, or bigger like a magnifying glass does – it simply reflects light straight back to show things as they really are. This is why you can use a mirror to check if your school uniform fits properly, because the reflection shows your true size!' WHERE id = '16e7d242-773f-4d3b-b2f3-3449a8eedbeb';
UPDATE questions SET explanation = 'Refraction happens when light bends as it passes from one material into another, like when a straw looks bent in a glass of water or when light passes through a prism. Option B correctly shows this bending of light as it moves between different materials. Remember that reflection (bouncing off a surface like a mirror) is different from refraction, so don''t confuse the two!' WHERE id = 'cb4e9236-a441-4a28-a9bd-dc3ed2d4c566';
UPDATE questions SET explanation = 'When red litmus paper stays red and doesn''t change color, it means the liquid is neither acidic nor alkaline - it is neutral. If the liquid were an alkali (option A), the red litmus paper would have turned blue, but since it stayed red, we know the sugary liquid has a neutral pH, just like pure water.' WHERE id = '37dcc14c-fa1a-4293-b081-1a7ec4edd664';
UPDATE questions SET explanation = 'Sulphuric acid is a strong acid because it completely breaks apart in water and can cause serious burns or damage to materials very quickly. The other acids listed - carbonic acid (found in fizzy drinks), citric acid (found in lemons), and tartaric acid (found in grapes) - are all weak acids that only partially break apart in water, which is why you can safely eat or drink things containing them.' WHERE id = '84e631af-c88b-4f0b-9f4f-d5a310d93898';
UPDATE questions SET explanation = 'Friction happens when surfaces rub against each other, and rough surfaces create more friction than smooth ones. Streamlining, ball bearings, and oiling all make surfaces smoother or reduce contact, which decreases friction. Increasing roughness does the opposite – it makes surfaces grip more and creates even more friction, just like how rough sandpaper grips better than smooth glass.' WHERE id = 'f523f597-a4f0-4f6e-8960-22c692d518a1';
UPDATE questions SET explanation = 'In a lever system, the load is the object or weight that needs to be moved or lifted. B is correct because it represents the load - the heavy object being lifted by the lever. A represents the fulcrum (the pivot point), while C shows the effort (the force you apply), and D is just part of the lever arm itself.' WHERE id = '3fdb7636-d43f-4d8c-bb27-827a9aed362a';
UPDATE questions SET explanation = 'A lightning conductor is a safety device that actually protects buildings by safely directing lightning strikes down to the ground, so it reduces the risk rather than increasing it. The other options all increase your danger because water, tall objects, and metal wires can attract lightning or help it travel to you during a thunderstorm.' WHERE id = 'e04ce8b8-b362-49e8-9cc5-f317399f4b94';
UPDATE questions SET explanation = 'In a parallel circuit, electricity has multiple paths to flow through, so if one bulb or device breaks, the others keep working because they have their own separate paths. This is why our homes use parallel circuits - when one light bulb stops working, the other lights in your house stay on! Option A is incorrect because it says the opposite - in parallel circuits, a break in one path does NOT affect the other paths, which is exactly what makes them so useful.' WHERE id = '2fda8214-ea5b-4bb4-9f9c-5c20405c7cf1';
UPDATE questions SET explanation = 'Friction happens when two surfaces rub against each other, like when you push a book across your desk or when your shoes grip the ground as you walk. This rubbing between touching surfaces is a contact force, which means the objects must be physically touching for friction to occur. While gravity pulls objects down and can press them together (which affects how strong friction is), gravity itself does not create the friction - it''s the contact between the surfaces that does.' WHERE id = '28a6f3f9-ea05-451b-a301-ed0665b84d7b';
UPDATE questions SET explanation = 'A lever is a simple machine because it has just one or two parts that work together to make our work easier, like a seesaw or a bottle opener. Simple machines like levers use basic movements to help us lift or move heavy objects with less effort. They are not complex machines because complex machines have many moving parts working together, like a bicycle or a car.' WHERE id = 'a30980b6-f085-448d-a2aa-e1d53b9d6817';
UPDATE questions SET explanation = 'In a first class lever, the pivot (fulcrum) is always positioned between the load and the effort, just like a seesaw where the middle support is between the two people. Second class levers have the load in the middle (like a wheelbarrow), while third class levers have the effort in the middle (like fishing rods or tweezers). Remember the order: First class = Fulcrum in middle, Second class = Load in middle, Third class = Effort in middle.' WHERE id = '47f4e2d2-668e-4251-a3d3-b08d7a60bcaa';
UPDATE questions SET explanation = 'When you rub two objects together, like when you drag your feet across a carpet or comb your hair, electrons move from one object to the other and create static electricity - that''s friction at work! Batteries, generators, and solar panels all produce current electricity that flows through wires, which is different from static electricity that builds up and stays in one place until it suddenly jumps (like a shock). Friction is the only way listed here that creates that buildup of electrical charge we call static electricity.' WHERE id = 'a52faac2-573c-4538-856d-c6cf13e156a4';
UPDATE questions SET explanation = 'When light from car headlights shines on white clothing at night, the white material reflects the light back strongly, making the pedestrian easy to spot from far away. This helps drivers see pedestrians in time to slow down or stop safely. Dark clothing would absorb the light instead of reflecting it, making it very difficult for drivers to notice people walking along the road.' WHERE id = '341b11b5-c1a6-4c18-be01-554f11950363';
UPDATE questions SET explanation = 'The liver is a very important organ that produces bile, a greenish liquid that helps break down fats in your food so your body can use them. Many students confuse the oesophagus with the intestines, but the oesophagus is actually just a muscular tube that pushes food down to your stomach – it''s the large intestine that absorbs water from undigested food. Remember that each organ in your digestive system has its own special job to keep you healthy and strong!' WHERE id = 'd16aace0-a91e-4837-baa7-ac505df3a80d';
UPDATE questions SET explanation = 'The ovary is the female reproductive organ that produces and stores eggs, so when you see a diagram showing the larger rounded structure where eggs develop, that''s the ovary. Students sometimes confuse this with the egg itself, but remember that the egg is much smaller and is actually produced inside the ovary before being released. Think of the ovary as a factory that makes eggs, not the egg itself!' WHERE id = '76119f34-f0db-4561-8365-b1d9fbeeac06';
UPDATE questions SET explanation = 'The uterus is a special organ in a woman''s body that acts like a safe, comfortable home where a baby grows and develops for about 9 months during pregnancy. While the vagina does receive sperms during reproduction (option A), this is not the uterus''s main job – the uterus''s most important function is to protect and nourish the growing baby until it is ready to be born. The ovaries, not the uterus, are responsible for producing ova (eggs).' WHERE id = '255a244e-dcaa-4ec7-bbec-f51a5601a90f';
UPDATE questions SET explanation = 'Mercury is the smallest planet in our solar system and sits right next to the Sun as the first planet. Venus might seem like a good choice because it''s the hottest planet, but it''s actually the second planet from the Sun, with Mercury being even closer. If you remember the order of planets starting from the Sun, it goes: Mercury, Venus, Earth, Mars, and then the outer planets.' WHERE id = '25eb994c-d422-4e70-b019-8548a27c6abd';
UPDATE questions SET explanation = 'Gravity is the invisible force of attraction between the Sun and the planets that pulls them toward the Sun, keeping them moving in curved paths called orbits instead of flying off into space. Magnetism might seem like a good answer because magnets also pull objects, but planets aren''t magnets and magnetic forces only work on certain metals, not on all the rocks and gases that make up planets. Friction and wind cannot work in space because there is no air in the empty space between planets.' WHERE id = '1f63c4bc-8ad0-40a3-99dd-58fa8e194db9';
UPDATE questions SET explanation = 'A solar eclipse happens when the Moon moves directly between the Earth and the Sun, blocking the Sun''s light and casting a shadow on Earth. Option B describes a lunar eclipse instead, which is when Earth blocks sunlight from reaching the Moon. The Sun is far too large and always stays in the center of our solar system, so it cannot pass between Earth and the Moon.' WHERE id = '07cb22d3-0c1d-477b-a131-ed3cd6f6040c';
UPDATE questions SET explanation = 'The planets orbit the Sun in this order from closest to farthest: Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, and Neptune. Mercury is the closest planet to the Sun because it has the smallest orbit, while Neptune is the farthest away. A helpful way to remember this order is to create a sentence where each word starts with the same letter as each planet in order!' WHERE id = '821ec34b-353a-4f49-a790-10a2701b692b';
UPDATE questions SET explanation = 'Fixing leaking pipes is an excellent way to conserve water because even a small leak can waste hundreds of litres of clean water every day that could be used by families and farms. When we leave taps running or use more water than we need, we are actually wasting water instead of conserving it. In Botswana where water is precious, every drop we save by fixing leaks helps ensure there is enough water for everyone.' WHERE id = '54bc0e69-5e8d-4e70-9417-be53877239fe';
UPDATE questions SET explanation = 'A barometer is a special instrument that measures air pressure, which is the weight of all the air pushing down on us from above. When air pressure changes, it helps us predict if the weather will be sunny, rainy, or stormy. While a thermometer measures temperature and other instruments measure wind speed or humidity, a barometer specifically tells us about the pressure of the air around us.' WHERE id = '02f47b63-ee6c-4a63-ad87-daa9254ce9da';
UPDATE questions SET explanation = 'Sound waves travel fastest through solids because the particles are packed very close together, allowing vibrations to pass quickly from one particle to the next. In gases like air, the particles are far apart, so sound moves much more slowly because each vibration takes longer to reach the next particle. This is why you can hear a train coming from far away if you put your ear to the railway track, but it takes longer to hear it through the air.' WHERE id = 'd12328a6-10ff-4311-9e44-1f79a404cbb5';
UPDATE questions SET explanation = 'A closed switch in a circuit diagram is shown by two lines that touch each other, allowing electricity to flow through without any gap. Option B shows an open switch where the lines don''t meet, which would stop the electricity from flowing. Remember, a closed switch is like a closed door that completes the path for electricity to travel around the circuit.' WHERE id = '24ba7661-abc0-43a9-932c-c12c02aadd8c';
UPDATE questions SET explanation = 'Backstreet abortions are very dangerous because they are done in unsafe places without proper medical care or clean equipment, which can cause serious bleeding and infections that put the mother''s life at risk. This is completely different from proper medical care, which aims to keep people healthy and safe. The other options describe positive health outcomes, but backstreet abortions actually cause serious harm to a woman''s health and can even lead to death.' WHERE id = '93660818-c7e6-4813-9d70-cedc27ea1732';
UPDATE questions SET explanation = 'When you add soap to soft water, it creates lots of bubbles and lathers easily, making it great for washing. Hard water contains dissolved minerals like calcium and magnesium that prevent soap from lathering well, so you need to use more soap to get bubbles. Remember, hard water has the minerals, not soft water, which is why option B is the opposite of what is true.' WHERE id = '1643a425-91ce-4777-8862-b98af01e9f91';
UPDATE questions SET explanation = 'Iron is magnetic, which means it is attracted to magnets, while sand is not magnetic at all. This means you can use a magnet to pull out all the iron filings from the mixture, leaving the sand behind. Filtration would not work here because both sand and iron filings are solid particles that would stay together on the filter paper.' WHERE id = '362f6c63-1b91-47d1-bc49-f44accdb2929';
UPDATE questions SET explanation = 'Sodium bicarbonate (baking soda) is a weak alkali because it only releases a small amount of hydroxide ions when dissolved in water, making it gentle and safe to use in cooking and cleaning. The other options - calcium hydroxide, potassium hydroxide, and sodium hydroxide - are all strong alkalis that release many hydroxide ions and can be dangerous to touch or swallow because they are very corrosive. You can tell sodium bicarbonate is weaker because it has a pH closer to 7, while strong alkalis have pH values much higher, around 12-14.' WHERE id = '56e70b7e-0a67-4530-b59b-ac174d0c35e8';
UPDATE questions SET explanation = 'In Botswana''s national immunization program, children receive vaccines to protect against tetanus, whooping cough, and diphtheria as part of routine childhood vaccinations. Typhoid fever is not included in the standard immunization schedule, though it may be given separately to people traveling to high-risk areas. The vaccines for tetanus, whooping cough, and diphtheria are often given together in one injection called the DPT vaccine.' WHERE id = 'c3d9c3f5-c778-4385-a348-b541074ad090';
UPDATE questions SET explanation = 'Looking directly at a solar eclipse can seriously damage your eyes because the sun''s rays are extremely powerful, even when partially covered by the moon. Specially made eclipse goggles have very strong filters that block out harmful rays and protect your eyes safely. Ordinary sunglasses might seem like they would work, but they are not strong enough to protect your eyes from the sun''s dangerous radiation during an eclipse.' WHERE id = '287ef75d-e2ac-4070-a3e9-b1a04a23f236';
UPDATE questions SET explanation = 'Tuberculosis (TB) is spread through the air when a person with TB coughs, sneezes, or talks, releasing tiny droplets that others can breathe in. This is why TB spreads easily in crowded places and why people with TB should cover their mouths when coughing. Unlike diseases such as malaria, TB is not spread by mosquitoes or through water, and it is not a sexually transmitted infection.' WHERE id = '271d4f38-bf92-4a4d-9798-d3b019f836e1';
UPDATE questions SET explanation = 'A cow is a consumer because it must eat other living things (like grass) to get energy and grow - it cannot make its own food. Producers are organisms like grass and trees that make their own food using sunlight, water, and air. Since the cow eats the grass rather than making food itself, it is definitely a consumer in the food chain.' WHERE id = 'b0fddccf-5224-44f0-aee3-ef5827901fb4';
UPDATE questions SET explanation = 'Levers are grouped into three types based on where the fulcrum, load, and effort are positioned: first class, second class, and third class levers. The fulcrum is actually the pivot point that all levers use, not a type of lever itself. Think of it this way: the fulcrum is like the hinge on a door - it''s a part that helps the lever work, but it''s not a category of lever.' WHERE id = '5bf7fc13-9cdc-4d1c-a339-8e05fb8a598f';
UPDATE questions SET explanation = 'Unlicensed drivers cause the most road accidents because they haven''t received proper training on road rules, safety procedures, and how to handle different driving situations. While drunken driving is also very dangerous and causes many accidents, statistics show that people driving without a license cause even more accidents because they simply don''t know how to drive safely. Bad roads and animals can contribute to accidents, but the driver''s skills and training matter most in preventing crashes.' WHERE id = 'ad7b58f6-95f8-4bb0-9d11-8fea418452d4';
UPDATE questions SET explanation = 'Looking at the data carefully, when we count all the accidents that were caused by drunken driving, we get a total of 75 accidents. You might be tempted to choose 70 if you missed counting some of the accidents or made a small adding mistake, but when you add up all the numbers properly, you will see that 75 is the correct total.' WHERE id = '35a034f4-d6e0-4fb0-bb89-5916b584e244';
UPDATE questions SET explanation = 'Fine salt dissolves faster than coarse salt because it has smaller particles with more surface area touching the water at once. When you shake both test tubes the same way, the fine salt in test tube A will disappear into the water much quicker than the larger coarse salt pieces in test tube B. Think of it like sugar - fine sugar dissolves faster in your tea than big sugar crystals would!' WHERE id = 'c0efd2e2-369d-4e84-b9da-9e218ef1e703';
UPDATE questions SET explanation = 'A secondary consumer is an animal that eats other animals that have already eaten plants. The snake is a secondary consumer because it eats animals like frogs or mice, which themselves ate insects or plants. A grasshopper is a primary consumer because it only eats plants, and a frog is also a primary consumer when it eats insects that feed on plants.' WHERE id = '3f2f9dab-2c96-449f-88d2-eebc963195e4';
UPDATE questions SET explanation = 'Combustion is a chemical reaction where substances burn with oxygen to produce new substances like ash and smoke, so it changes materials rather than separating them. Filtration, magnetism, and evaporation are all separation methods that physically separate different parts of a mixture without changing what the substances are made of—for example, you can use a magnet to separate iron filings from sand, or filter to separate water from soil.' WHERE id = '03be4956-f892-4321-ba33-98470b8eac77';
UPDATE questions SET explanation = 'When you boil hard water, the heat causes some of the dissolved minerals (like calcium) to form solid deposits that settle at the bottom or stick to the pot, making the water softer. Cooling or freezing the water doesn''t change the minerals dissolved in it - they stay mixed in the water whether it''s hot or cold. Evaporating would remove the water and leave all the minerals behind, which is the opposite of what we want!' WHERE id = '59f839f5-1041-41c1-a25b-ebfaf4c5c725';
UPDATE questions SET explanation = 'At a cold front, a mass of cold air moves in and pushes underneath the warm air that was there before, causing the cold air to replace the warm air at ground level. While it''s true that warm air does rise when this happens (option C), that''s just part of what occurs – the main thing that defines a cold front is that cold air is taking the place of warm air. Think of it like when a cool breeze comes through your window and pushes out the warm air in your room!' WHERE id = 'fbc9eedc-afca-4d94-9a61-901f883f6c12';
UPDATE questions SET explanation = 'When Tiroyaone and his friends visit the park together for game viewing, they are enjoying time with each other and having fun as a group, which is a social benefit of tourism. Social benefits are about people spending quality time together and building friendships through activities. While tourism can bring money to an area (economical benefit), this example focuses on the friendship and enjoyment the group experiences together.' WHERE id = 'bf4af0a9-770e-4093-9321-7e6a5ff99c8a';
UPDATE questions SET explanation = 'Looking at the diagram, you can see particles that are spread far apart and moving randomly in all directions, which is exactly how gas particles behave. Solids might seem tempting because we can see individual particles, but in solids the particles would be tightly packed together in a fixed pattern, not spread out like this. The wide spacing and freedom of movement shown here is the key feature that tells us this is a gas.' WHERE id = 'cc820f2f-6bc1-424c-927a-12f5128214be';
UPDATE questions SET explanation = 'Family planning helps people decide when to have children, allowing them to first finish their education and achieve their goals like completing their studies. When people can plan their families properly, they avoid negative consequences like being unable to care for a baby or having to leave school early. This is why completion of studies is a benefit of family planning, while the other options are problems that family planning helps to prevent.' WHERE id = '3706c0b7-1a21-46c3-8d21-5d4c20ead3bb';
UPDATE questions SET explanation = 'The Earth travels around the Sun in a path called an orbit, taking one full year to complete this journey. Long ago, people thought the Sun moved around the Earth because it appears to rise and set each day, but scientists discovered that it''s actually our Earth that is spinning and moving around the much larger Sun. The Sun stays at the center of our solar system while all the planets, including Earth, revolve around it.' WHERE id = '60bb3b66-cc00-4af1-aca1-4388c4d515c7';
UPDATE questions SET explanation = 'The Sun is a source of light because it produces its own light through burning gases, just like a candle flame or light bulb makes light. The Moon might seem like it glows, but it actually just reflects light from the Sun like a mirror does—neither the Moon nor a mirror can make their own light. Windows and mirrors only allow light to pass through or bounce off them, but they cannot create light themselves.' WHERE id = '6c1753a5-1193-4b81-91b7-8fe16acbf9dd';
UPDATE questions SET explanation = 'A solution is a special mixture where one substance dissolves completely into another, like sugar in water, so the particles are too tiny to be trapped by a filter. Suspensions, on the other hand, have larger particles that eventually settle at the bottom and can be separated by filtering, like muddy water. Once a mixture forms a solution, the only way to separate it is through other methods like evaporation or distillation.' WHERE id = '7c2e3651-ea00-48ec-9951-8790521cc2f4';
UPDATE questions SET explanation = 'A lunar eclipse happens when the Earth moves directly between the Sun and the Moon, blocking sunlight from reaching the Moon''s surface. This causes the Moon to darken or turn reddish because it sits in Earth''s shadow. Option A describes a solar eclipse instead, which is when the Moon blocks the Sun''s light from reaching Earth.' WHERE id = 'de626135-5bd6-462c-b845-487e4e8c62f1';
UPDATE questions SET explanation = 'A warm front happens when warm air moves forward and slides over the cold air that was there before, bringing moisture and humidity to the area. You might think cold air replaces warm air (option A), but that would actually be a cold front, which is the opposite situation. The key is to remember that a warm front means the warm air is advancing and taking over the space where cold air used to be.' WHERE id = '11bef27b-3553-4cf7-bb94-7499c95a4a58';
UPDATE questions SET explanation = 'Drying mophane worms is a traditional scientific practice because it uses the sun''s heat to preserve food by removing water, which stops bacteria from spoiling the worms. This method of food preservation has been used by Batswana for many generations and follows scientific principles of dehydration. The other options are either cultural practices without scientific basis or don''t make practical sense, like wearing heavy clothes when it''s hot.' WHERE id = 'e05dedc8-9d38-4703-ab27-2149bfdbe4db';
UPDATE questions SET explanation = 'In a food chain, the arrow shows the direction energy flows, which means it points from what is eaten to what eats it. Since grass is eaten by the hippo, and the hippo is eaten by the lion, the arrows must go Grass → Hippo → Lion. Option A might seem tempting because it lists the animals in the story order, but remember the arrows must always point from the food to the feeder, starting with plants that make their own food.' WHERE id = '66fc739f-ebc5-4f3a-b80c-4ede84db1659';
UPDATE questions SET explanation = 'Polluted water contains harmful germs, chemicals, and dirt that can make people very sick with diseases like cholera, diarrhea, and typhoid fever. When these dangerous things enter our bodies through drinking, they attack our health instead of helping us stay strong. This is why we must always drink clean, safe water from protected sources like treated taps or boiled water.' WHERE id = 'f430d9cb-f1c0-476c-954d-0f5f96b46035';
UPDATE questions SET explanation = 'A food chain must show how energy flows from the sun to plants, then to animals that eat plants, and finally to animals that eat other animals. Option A correctly shows the sun giving energy to grass (producer), which is eaten by the grasshopper (herbivore), which is then eaten by the frog (carnivore). Option B has the chain backwards—energy cannot flow from animals back to the sun!' WHERE id = 'a362369d-5751-4392-88d5-d9f7db8aa505';
UPDATE questions SET explanation = 'Bacteria are decomposers because they break down dead plants and animals into simpler substances that return nutrients to the soil. Lions and zebras are consumers that eat other living things, while grass is a producer that makes its own food through photosynthesis. Decomposers like bacteria play a very important role in nature by recycling nutrients so that new plants can grow.' WHERE id = '2da77546-7bb7-44b3-aa4a-46b4b3546fda';
UPDATE questions SET explanation = 'A community in ecology is made up of all the different types of living things sharing the same place, like having different plants, animals, insects, and birds all living together in a forest or savanna. When you see only one type of animal or plant together, like a herd of zebras or a group of mopane trees, that''s called a population, not a community. A true community needs many different species interacting with each other in the same area.' WHERE id = '8b9edb5c-63db-4dda-b8de-01d26f8a7a2e';
UPDATE questions SET explanation = 'Solar energy is renewable because the sun keeps shining every day and will never run out in our lifetime, so we can use it over and over again. Coal, natural gas, and petroleum are non-renewable because once we burn them, they are gone forever, and it takes millions of years for the Earth to make more of them. We should use more renewable energy sources like solar power to protect our environment and save resources for the future.' WHERE id = '599740ff-ea6e-4c9b-ac93-9b83dcf6723d';
UPDATE questions SET explanation = 'When a candle burns, the wax (which is a chemical) changes into heat energy that you can feel and light energy that helps you see in the dark. This is why we say chemical energy is converted to heat and light energy. Option B might seem correct because candles can make a crackling sound sometimes, but the main energy change in a burning candle is always chemical energy turning into heat and light, not sound.' WHERE id = '7b9f939c-d6eb-4f6b-8230-9cc51b75bf40';
UPDATE questions SET explanation = 'When using a lever, the effort is the force you apply to make the lever work, and looking at the diagram, you can see that point A is where the person pushes down to lift the load. Point B might seem like a good choice because it''s in the middle, but that''s actually the fulcrum (the pivot point where the lever turns), not where you apply your pushing force. The effort always comes from where you put in your own force to move something.' WHERE id = 'c285fa3d-0004-4c73-91cf-59a070c8937e';
UPDATE questions SET explanation = 'Lightning looks for the easiest path to reach the ground, so it usually strikes the tallest objects first because they are closest to the clouds where lightning forms. Tall towers are at high risk because they stick up much higher than short buildings, flat ground, or grass, making them like a bridge that brings the lightning closer to Earth.' WHERE id = 'c535b7d9-7d5d-4ee1-88cc-244e3d2cf810';
UPDATE questions SET explanation = 'Vinegar is a weak acid because it contains acetic acid, which only releases some of its hydrogen ions when mixed with water, making it acidic but not very strong. You can safely use vinegar in cooking and cleaning because it''s much milder than strong acids like battery acid, which can cause serious burns. If vinegar were neutral like water, it wouldn''t have that sour taste or be able to clean things the way it does!' WHERE id = 'fd9ee2d7-78e0-4d0a-92d9-6eae29ed76e8';
UPDATE questions SET explanation = 'In our homes, we use parallel circuits because each electrical device (like lights and TV) can work independently - if one bulb breaks, the others keep working, and each device gets the full voltage it needs. A series circuit would not work well because if one device stops working, everything else would also stop working, just like when one bulb breaks in some old Christmas lights, they all go off. Parallel circuits also let us control each device separately with its own switch, which is very practical for everyday use.' WHERE id = 'e1a7a105-fc8a-436f-9238-6c4414cedd6d';
UPDATE questions SET explanation = 'Light travels incredibly fast at 300,000 kilometers per second, which means it could go around the Earth more than 7 times in just one second! This is much faster than the other options – for example, 300 km/s would be too slow for light to reach us from the Sun in only 8 minutes like it actually does. Remember this speed by thinking "3" with five zeros after it: 300,000 km/s.' WHERE id = 'f6412fbb-d403-4471-ae01-2e816e3045b5';
UPDATE questions SET explanation = 'Friction is actually very helpful because it creates a grip between our feet and the ground, which stops us from slipping when we walk or run. While it''s true that friction does slow down vehicles and wear out shoes, these are problems caused by friction, not benefits. A benefit is something good that helps us, and without friction, we wouldn''t be able to walk at all – we would just slide around like on ice!' WHERE id = 'e9c8d6a6-d9fd-48cd-ab02-d752765be69a';
UPDATE questions SET explanation = 'A switch works like a gate in an electric circuit - when you press it ON, it closes the circuit and allows electricity to flow through, making your bulb light up or your device work. When you press it OFF, it opens the circuit and stops the electricity from flowing. The switch does not make electricity (that''s what a battery or generator does) or store it - it simply controls whether the electricity can flow or not.' WHERE id = '209c69e6-59e2-4ef6-8570-5e670c894897';
UPDATE questions SET explanation = 'When you put Eno in water, it dissolves completely and disappears into the liquid, making it soluble, while sand does not dissolve and settles at the bottom, making it insoluble. Some students might think salt is insoluble, but if you stir salt in water, it dissolves completely just like sugar does – both are soluble substances that disappear into water. Maize meal and flour may seem to mix with water, but they don''t actually dissolve; they just float around and eventually settle or form a cloudy mixture.' WHERE id = '419d378e-6301-4b88-be45-957ab0f1f9e1';
UPDATE questions SET explanation = 'Hard water contains dissolved mineral salts like calcium and magnesium, which prevent soap from forming a good lather and instead create scum or foam on the surface. Soft water, on the other hand, has few or no dissolved salts, so soap easily creates lots of rich lather when you wash with it. This is why soft water is better for washing clothes and bathing, as you need less soap to get things clean!' WHERE id = 'bde9d4e2-089e-45cd-a8a6-a82bac98c7cc';
UPDATE questions SET explanation = 'Jackals are not protected animals in Botswana because they are common and not at risk of disappearing. Animals like cheetahs, vultures, and giraffes are protected by law because their numbers are low and they need special care to survive. Protected animals cannot be hunted or harmed, but jackals can be controlled when they cause problems for farmers.' WHERE id = '8b74a39a-d3dd-4250-8609-519413a4b2fc';
UPDATE questions SET explanation = 'Weather describes what the atmosphere is like right now or over just a few days – like when you check if it''s sunny, rainy, or windy today before going to school. Option B describes climate, not weather, because climate is the pattern of atmospheric conditions over many years, such as knowing that Botswana is generally hot and dry. Remember: weather changes quickly (day to day), while climate is the long-term average!' WHERE id = '926d91a9-d8bd-4121-8860-66dac144de10';
UPDATE questions SET explanation = 'Sedimentation is a water treatment method where heavy dirt particles and solid materials sink to the bottom of a container, leaving cleaner water on top. This process is commonly used at water treatment plants and even in our homes when we let muddy water settle. Magnetism, sublimation, and combustion are not used for cleaning water because they involve attracting metals, changing solids directly to gas, and burning materials respectively.' WHERE id = '1ff463f1-83eb-495c-854e-94590c6756b8';
UPDATE questions SET explanation = 'Evaporation can happen at any temperature - you can see wet clothes drying even on a cool day - while boiling only happens when water reaches exactly 100°C. This is why a puddle slowly disappears in the sun without bubbling, but water in a pot must get very hot before it starts to boil with bubbles. Though boiling looks faster because of all the bubbles, evaporation is actually always happening whenever there is liquid water exposed to air.' WHERE id = 'be462faf-0c82-419f-9d0a-a3f74ac0791f';
UPDATE questions SET explanation = 'Copper wire is a conductor of electricity because it allows electric current to flow through it easily, which is why we use copper in electrical wires at home and in appliances. Materials like plastic, rubber, and wood are insulators that block electricity from flowing through them – that''s why electrical wires are covered with plastic or rubber coating to keep us safe from electric shocks. Metals like copper are excellent conductors, while most non-metals are insulators.' WHERE id = '95ffb3dc-a6c6-4117-b56b-1d4ca094b9b8';
UPDATE questions SET explanation = 'When water freezes into ice, the water molecules arrange themselves into a special pattern with more space between them, making ice less dense than liquid water. This is why ice floats on top of water in your drink or in a pond! Many students think density increases (option A) because ice feels solid and hard, but remember that density is about how tightly packed the molecules are, not how hard something feels.' WHERE id = '44925fe7-017d-4e53-be54-53de29ff27dc';
UPDATE questions SET explanation = 'A lunar eclipse happens when the Earth moves directly between the Sun and the Moon, blocking sunlight from reaching the Moon''s surface. You might have confused this with option A, which actually describes a solar eclipse—that''s when the Moon passes between the Earth and the Sun, blocking our view of the Sun. Remember: lunar eclipse = Earth in the middle, solar eclipse = Moon in the middle!' WHERE id = '1249927e-6582-4832-9bea-bd2dc8558860';
UPDATE questions SET explanation = 'Pasteurization is a special process where we heat milk to a specific temperature (not boiling!) and then cool it down quickly to kill harmful germs that could make us sick. This is different from boiling milk at a high temperature because pasteurization uses a lower, carefully controlled temperature that kills the germs but keeps the milk''s good taste and nutrients. The quick heating and cooling makes milk safe to drink while keeping it fresh and healthy for you!' WHERE id = '4e938ec0-3450-42cd-a8a4-bcc03db6ed99';
UPDATE questions SET explanation = 'An economist studies how people use money and resources in business and government, which involves mathematics but not science and technology in the same way other careers do. A pharmacist must understand chemistry to prepare medicines, a mechanic needs to know how engines and machines work using physics, and an engineer applies scientific principles to design and build structures or systems. While economics uses some mathematical tools, it focuses on human behavior and financial systems rather than applying scientific knowledge about the natural world.' WHERE id = '5369d7f9-c700-4d9e-9773-dfc82c96e155';
UPDATE questions SET explanation = 'Whales are mammals that live their entire lives in water, with special body features like flippers and a streamlined shape that help them swim in oceans and seas. While birds like ducks can swim on water''s surface, they don''t live in water like whales do - they return to land to rest and build nests. Cats and ants are land animals that would struggle to survive in water because they lack the special adaptations needed for aquatic life.' WHERE id = '792fc7e0-224e-4ba3-82a7-89b722f30288';
UPDATE questions SET explanation = 'During a drought, there is very little water available, which means plants cannot grow well and many will die. When plants die, animals lose their food and water sources, so many animals will also die or move away to find better conditions, causing the population to decrease. More rainfall (option D) is about weather changes, not about what happens to living things during the drought itself.' WHERE id = 'f7a91dba-3210-4696-8736-065e0463eb11';
UPDATE questions SET explanation = 'Conservation means protecting our natural environment so that future generations can also enjoy Botswana''s amazing wildlife and plants, like elephants, lions, and mopane trees. While people can earn money by working in game reserves, this is just one job opportunity, not the main reason we protect nature—conservation is really about making sure these precious plants and animals don''t disappear forever. By conserving today, we ensure that your children and grandchildren will still be able to see the beautiful wildlife that makes Botswana special.' WHERE id = '50c4c4a6-e001-409e-adeb-6dbdc58da31f';
UPDATE questions SET explanation = 'When you see a weather symbol with a bright sun and lines coming off to the side, those lines represent wind movement, showing us it will be sunny and windy. Some students might think option B (just sunny) is correct because they notice the sun first, but remember that the extra lines are very important - they always mean wind is present in the forecast. Weather symbols combine different elements to give us complete information about what to expect outside.' WHERE id = '2e7a5e45-0094-43f5-b51a-657100002bb0';
UPDATE questions SET explanation = 'A wind vane is a simple tool with an arrow that spins freely on top of a pole, and it always points in the direction where the wind is coming from. While it shows wind direction perfectly, it cannot measure how fast the wind is blowing – that''s what an anemometer is for! The wind vane just rotates to follow the wind''s direction, but it doesn''t change or control which way the wind actually blows.' WHERE id = 'a1cce8f9-3a01-42ab-961d-98cf4a75f173';
UPDATE questions SET explanation = 'Botswana is a landlocked country, which means it is completely surrounded by other countries and has no coastline where it touches the sea. This is why we do not have ocean habitats in Botswana, even though we have desert areas like the Kalahari, rivers like the Okavango, and swamps in the Okavango Delta. To see an ocean, people from Botswana would need to travel to neighbouring countries like Namibia or South Africa.' WHERE id = '50ed287d-95b2-4ac7-af97-ba12b2e58174';
UPDATE questions SET explanation = 'When fuels like petrol, diesel, coal, or wood are burned, they release smoke and harmful gases into the air, which is what we call air pollution. While cutting down trees is harmful to the environment because trees clean the air by absorbing carbon dioxide, it doesn''t directly release pollutants into the air the way burning does. Burning fuels in vehicles, factories, and cooking fires is one of the main causes of dirty air in our cities and towns.' WHERE id = 'adfd1029-f1db-4180-ba52-af8c315c8b8f';
UPDATE questions SET explanation = 'Animals that eat both plants and animals are called omnivores because "omni" means "all" - they eat all types of food. You might have been tempted to choose herbivores or carnivores, but remember that herbivores only eat plants (like goats and zebras) and carnivores only eat meat (like lions and leopards). Omnivores like baboons, chickens, and even humans eat a mixture of both plants and animals!' WHERE id = 'dd947e45-89e8-4224-9f38-94f1934ca787';
UPDATE questions SET explanation = 'Oxygen is the gas we breathe in to stay alive, and it makes up about 21% of our atmosphere, but it does not trap heat like greenhouse gases do. Greenhouse gases like carbon dioxide, methane, and water vapour act like a blanket around Earth, trapping the sun''s heat and making our planet warmer. Oxygen simply passes heat through without trapping it, which is why it is not considered a greenhouse gas.' WHERE id = '568e9e8d-9b74-478d-838d-f89644725881';
UPDATE questions SET explanation = 'Fixing leaking taps is an excellent way to conserve water because even small drips can waste hundreds of litres each month that just go down the drain. Watering plants during the day might seem helpful, but actually wastes water since the hot sun causes much of it to evaporate before the plants can use it - it''s better to water early in the morning or evening. Remember, in Botswana where water is precious, every drop we save makes a difference!' WHERE id = '4bf37209-57dc-419e-9c75-2fa0cdf62dfc';
UPDATE questions SET explanation = 'The ozone layer is like a protective shield high up in our atmosphere that blocks harmful ultraviolet (UV) rays from the sun, which can cause skin cancer and damage our eyes. While the atmosphere does help keep Earth warm and contains oxygen, the ozone layer''s special job is specifically to filter out these dangerous UV rays before they reach us. Think of it as Earth''s natural sunscreen protecting all living things!' WHERE id = '8de70b24-8f53-4a98-b6e4-585dfc3caaf9';
UPDATE questions SET explanation = 'A second class lever always has the load positioned between the pivot (fulcrum) and the effort, which makes it easier to lift heavy things - just like when you use a wheelbarrow where the wheel is the pivot, the load sits in the middle, and you lift the handles with effort. You might have thought the pivot goes between effort and load (option A), but that describes a first class lever like a seesaw. Remember the "2" in second class means the load is in position number 2, right in the middle!' WHERE id = '520982a4-b566-4603-9910-f2e239df0049';
UPDATE questions SET explanation = 'Gravity is the force that pulls all objects downward towards the centre of the Earth, which is why when you drop something, it always falls down rather than floating away. Friction is a different force that happens when two surfaces rub against each other, like when you try to push a heavy box across the floor. Gravity keeps us on the ground and makes things fall when we let them go.' WHERE id = '7fd9bac3-ae68-4af4-8009-c7ad06af4258';
UPDATE questions SET explanation = 'Coal is a non-renewable energy source because it formed from ancient plants buried deep underground millions of years ago, and once we use it up, it cannot be replaced in our lifetime. Wind, solar, and hydroelectric power are all renewable sources because they come from natural processes that keep happening - the sun keeps shining, wind keeps blowing, and water keeps flowing in rivers. Coal takes millions of years to form, so we must use it wisely while developing more renewable energy sources for Botswana''s future.' WHERE id = 'c2a524f9-f81d-4074-90f3-0315309894af';
UPDATE questions SET explanation = 'A thermometer is an instrument that measures temperature, which tells us how hot or cold something is. You can use a thermometer to measure the temperature of the air, water, or even your body when you''re sick. Wind speed is measured by a different instrument called an anemometer, not a thermometer.' WHERE id = '0c6f83e2-5cb6-463f-9feb-4d2f1f6f9fc3';
UPDATE questions SET explanation = 'During puberty, girls experience several body changes, and one of the most common signs is the growth of pubic hair in the private areas of the body. While a deep voice, broader shoulders, and facial hair are changes that happen to boys during puberty, girls develop different characteristics like pubic hair growth, breast development, and the start of menstruation. These changes are all normal and happen because your body is growing and maturing.' WHERE id = 'd764ae6f-8707-48be-b763-430dcf4cd745';
UPDATE questions SET explanation = 'The ovaries are two small organs in a woman''s body that make egg cells, which are needed to create a baby when they join with sperm. Some students might think the uterus (womb) is the ovary because that''s where the baby grows, but the ovaries only make the eggs before they travel to the uterus. While ovaries do produce hormones, these hormones are for females, not for boys.' WHERE id = 'c924d50c-6f12-4de5-a4ec-6fc50781057e';
UPDATE questions SET explanation = 'Fertilisation is the special moment when a sperm cell from the father joins together with an egg cell from the mother to start creating a new baby. This joining usually happens in the mother''s fallopian tube after the egg is released from the ovary. Remember that releasing the egg (option A) happens before fertilisation, while the baby being born (option C) happens many months after fertilisation has already occurred.' WHERE id = '86af59ab-b991-4a2b-9623-dd6f4cf1e8e9';
UPDATE questions SET explanation = 'Peer pressure is a cause of teenage pregnancy because when friends or peers encourage teenagers to have sex before they are ready, some may give in even though they know the risks. Good parenting actually helps prevent teenage pregnancy because supportive parents teach their children about making responsible choices and waiting until they are older. Abstaining from sex and staying in school are both ways to prevent teenage pregnancy, not causes of it.' WHERE id = '44788455-026a-47d5-af9c-bc15a1d7dc2f';
UPDATE questions SET explanation = 'Rhinos are the most protected animals in Botswana because they are critically endangered and face threats from poaching for their horns, which makes them need special armed guards and strict laws to keep them safe. While hippos are also protected as wild animals, they are not as endangered as rhinos and don''t need the same high level of security. Cows and donkeys are domestic animals that people own, so they don''t need government protection like endangered wildlife.' WHERE id = 'aa0e9e98-d5b1-44fc-9294-b3cb333f5c8d';
UPDATE questions SET explanation = 'Alexander Graham Bell was a famous inventor who created the telephone in 1876, which allowed people to talk to each other over long distances for the first time. While Thomas Edison invented the light bulb around the same time, Bell''s important contribution to science was making voice communication possible through wires. The wheel was invented thousands of years before Bell was even born, and tourism is not an invention but an activity people do when they travel.' WHERE id = '2f8ec92a-f3d6-4de7-ab61-78dd48e86f06';
UPDATE questions SET explanation = 'When a solid changes into a liquid at point A, we call this process melting, like when ice cubes melt into water on a hot day. Boiling and evaporation are incorrect because these processes happen at point B where a liquid changes into a gas, not where a solid becomes a liquid.' WHERE id = '2f9df84e-0c79-4239-8017-1abdbd1c2269';
UPDATE questions SET explanation = 'When a liquid changes into a solid state, we call this process freezing, which is what happens at point B where the substance is becoming solid. You might think it''s cooling because the temperature is dropping, but cooling just means losing heat and can happen in any state, while freezing is the specific change from liquid to solid. Remember, melting is the opposite (solid to liquid) and evaporation is when liquid becomes gas.' WHERE id = '68c559f9-70cc-49d9-8375-237ab9b8ad52';
UPDATE questions SET explanation = 'Salt dissolves fastest when two conditions are met: the water must be hot and the salt particles must be small. Hot water gives particles more energy to move and break apart the salt, while small particles have more surface area exposed to the water, allowing them to dissolve quickly. Although small particles in cold water (option A) will dissolve faster than large particles, the lack of heat slows down the process compared to hot water with small particles.' WHERE id = 'fd004d46-8b99-4532-b305-67279e992593';
UPDATE questions SET explanation = 'Boiling hard water over fire is the correct method because heating removes the minerals like calcium and magnesium that make water hard. Filtering through cloth might seem right, but it only removes dirt and solid particles, not the dissolved minerals that cause hardness. When you boil hard water, the heat causes chemical changes that make those minerals settle out, leaving you with softer water.' WHERE id = 'e1825bbf-c308-43e6-813d-58e60b2886a0';
UPDATE questions SET explanation = 'When a cold front moves through an area, a mass of cold air pushes forward and slides underneath the warm air that was there before, forcing the warm air to rise quickly. This means the cold air is replacing the warm air at ground level, which is why we feel a sudden drop in temperature when a cold front passes. While it''s true that warm air does rise during this process (option B), that''s what happens because of the cold front, not what the cold front itself is – a cold front is specifically about cold air moving in to take the place of warm air.' WHERE id = 'cb92fc43-8cd8-4f36-a939-3b06471c89cb';
UPDATE questions SET explanation = 'Carbon dioxide is a greenhouse gas because it traps heat from the sun in Earth''s atmosphere, like a blanket keeping our planet warm. Oxygen and nitrogen make up most of the air we breathe, but they don''t trap heat the same way, which is why they are not greenhouse gases. When we burn fuels or cut down trees, we add more carbon dioxide to the air, making Earth warmer than it should be.' WHERE id = '7c7c3fac-a744-4fdb-8574-1811f7ee3bae';
UPDATE questions SET explanation = 'The blanket of gases that wraps around our entire Earth is called the atmosphere. While the ozone layer, stratosphere, and troposphere are all important parts within the atmosphere, they are just individual layers, not the name for the whole covering of gases around our planet. Think of it like this: your school uniform has different parts like a shirt and trousers, but "uniform" is the name for the complete outfit, just as "atmosphere" is the name for all the gas layers together.' WHERE id = 'd59379f6-40ea-497a-b020-7cdc55a7e93f';
UPDATE questions SET explanation = 'Lightning is very dangerous and seeks the easiest path to the ground, so the safest place during a thunderstorm is indoors away from windows, where the building''s structure protects you. Never stand under tall trees during lightning storms because lightning often strikes the tallest objects, and you could be hit or injured by the electrical current traveling through the tree. Open fields and metal objects are also extremely dangerous because they attract lightning strikes.' WHERE id = 'ec702d8f-ef2b-4c07-942c-9ad529dab561';
UPDATE questions SET explanation = 'Chlorophyll is the green substance in plant leaves that captures energy from sunlight, which plants need to make their own food through photosynthesis. Without chlorophyll to absorb the sun''s light energy, plants couldn''t convert carbon dioxide and water into the sugar they need to grow. While roots do absorb water from soil, that''s a different job done by root hairs, not by chlorophyll.' WHERE id = '65bb8694-30e9-4cc2-ba0f-a2360bce4739';
UPDATE questions SET explanation = 'Tweezers are a third class lever because the effort (where your fingers squeeze) is between the fulcrum (the joined end) and the load (what you''re picking up). A wheelbarrow might seem similar, but it''s actually a second class lever because the load is between the fulcrum (the wheel) and the effort (the handles you lift). Remember, in third class levers, you always apply force in the middle!' WHERE id = '40921452-4d9e-44df-ad3a-dc67d372f82b';
UPDATE questions SET explanation = 'Copper is indeed a good conductor of electricity, which is why it is commonly used in electrical wires throughout homes and buildings in Botswana and around the world. Metals like copper, iron, and aluminum allow electricity to flow through them easily, so option A is incorrect because most metals are actually good conductors, not poor ones. Materials like rubber and wood are insulators that do not allow electricity to pass through easily, which is why rubber is used to cover electrical wires to keep us safe.' WHERE id = 'e40a1f7c-2af7-4f13-812d-595a09837932';

COMMIT;
